import{_ as e}from"./plugin-vue_export-helper.21dcd24c.js";import{f as p}from"./app.10609971.js";const r={},a=p('<h1 id="\u79EF\u5206\u7CFB\u7EDF" tabindex="-1"><a class="header-anchor" href="#\u79EF\u5206\u7CFB\u7EDF" aria-hidden="true">#</a> \u79EF\u5206\u7CFB\u7EDF</h1><p>\u5BF9\u4E8E\u4E00\u4E2A\u5DE5\u7A0B\u5E08\u6765\u8BF4\uFF0C\u5982\u679C\u8981\u8FFD\u6C42\u957F\u8FDC\u53D1\u5C55\uFF0C\u4F60\u5C31\u4E0D\u80FD\u4E00\u76F4\u53EA\u628A\u81EA\u5DF1\u653E\u5728\u6267\u884C\u8005\u7684\u89D2\u8272\uFF0C\u4E0D\u80FD\u53EA\u662F\u4E00\u4E2A\u4EE3\u7801\u5B9E\u73B0\u8005\uFF0C\u4F60\u8FD8\u8981\u6709\u72EC\u7ACB\u8D1F\u8D23\u4E00\u4E2A\u7CFB\u7EDF\u7684\u80FD\u529B\uFF0C\u80FD\u7AEF\u5230\u7AEF\uFF08end to end\uFF09\u5F00\u53D1\u4E00\u4E2A\u5B8C\u6574\u7684\u7CFB\u7EDF\u3002\u8FD9\u5176\u4E2D\u7684\u5DE5\u4F5C\u5C31\u5305\u62EC\uFF1A\u524D\u671F\u7684\u9700\u6C42\u6C9F\u901A\u5206\u6790\u3001\u4E2D\u671F\u7684\u4EE3\u7801\u8BBE\u8BA1\u5B9E\u73B0\u3001\u540E\u671F\u7684\u7CFB\u7EDF\u4E0A\u7EBF\u7EF4\u62A4\u7B49\u3002</p><p>\u524D\u9762\u6211\u4EEC\u8FD8\u63D0\u5230\u8FC7\uFF0C\u5927\u90E8\u5206\u5DE5\u7A0B\u5E08\u90FD\u662F\u505A\u4E1A\u52A1\u5F00\u53D1\u7684\u3002\u5F88\u591A\u5DE5\u7A0B\u5E08\u90FD\u89C9\u5F97\uFF0C\u505A\u4E1A\u52A1\u5F00\u53D1\u6CA1\u5565\u6280\u672F\u542B\u91CF\uFF0C\u6CA1\u6709\u6210\u957F\uFF0C\u5C31\u662F\u7B80\u5355\u7684 CRUD\uFF0C\u7FFB\u8BD1\u4E1A\u52A1\u903B\u8F91\uFF0C\u6839\u672C\u7528\u4E0D\u4E0A\u4E13\u680F\u4E2D\u8BB2\u7684\u8BBE\u8BA1\u539F\u5219\u3001\u601D\u60F3\u3001\u6A21\u5F0F\u3002</p><p>\u6240\u4EE5\uFF0C\u9488\u5BF9\u8FD9\u4E24\u4E2A\u666E\u904D\u7684\u73B0\u8C61\uFF0C\u4ECA\u5929\uFF0C\u6211\u901A\u8FC7\u4E00\u4E2A\u79EF\u5206\u5151\u6362\u7CFB\u7EDF\u7684\u5F00\u53D1\u5B9E\u6218\uFF0C\u4E00\u65B9\u9762\u7ED9\u4F60\u5C55\u793A\u4E00\u4E2A\u4E1A\u52A1\u7CFB\u7EDF\u4ECE\u9700\u6C42\u5206\u6790\u5230\u4E0A\u7EBF\u7EF4\u62A4\u7684\u6574\u4E2A\u5F00\u53D1\u5957\u8DEF\uFF0C\u8BA9\u4F60\u80FD\u4E3E\u4E00\u53CD\u4E09\u5730\u5E94\u7528\u5230\u6240\u6709\u5176\u4ED6\u7CFB\u7EDF\u7684\u5F00\u53D1\u4E2D\uFF0C\u53E6\u4E00\u65B9\u9762\u4E5F\u7ED9\u4F60\u5C55\u793A\u5728\u770B\u4F3C\u6CA1\u6709\u6280\u672F\u542B\u91CF\u7684\u4E1A\u52A1\u5F00\u53D1\u4E2D\uFF0C\u5B9E\u9645\u4E0A\u90FD\u8574\u542B\u4E86\u54EA\u4E9B\u8BBE\u8BA1\u539F\u5219\u3001\u601D\u60F3\u3001\u6A21\u5F0F\u3002</p><h2 id="\u9700\u6C42\u5206\u6790" tabindex="-1"><a class="header-anchor" href="#\u9700\u6C42\u5206\u6790" aria-hidden="true">#</a> \u9700\u6C42\u5206\u6790</h2><p>\u79EF\u5206\u662F\u4E00\u79CD\u5E38\u89C1\u7684\u8425\u9500\u624B\u6BB5\uFF0C\u5F88\u591A\u4EA7\u54C1\u90FD\u4F1A\u901A\u8FC7\u5B83\u6765\u4FC3\u8FDB\u6D88\u8D39\u3001\u589E\u52A0\u7528\u6237\u7C98\u6027\uFF0C\u6BD4\u5982\u6DD8\u5B9D\u79EF\u5206\u3001\u4FE1\u7528\u5361\u79EF\u5206\u3001\u5546\u573A\u6D88\u8D39\u79EF\u5206\u7B49\u7B49\u3002\u5047\u8BBE\u4F60\u662F\u4E00\u5BB6\u7C7B\u4F3C\u6DD8\u5B9D\u8FD9\u6837\u7684\u7535\u5546\u5E73\u53F0\u7684\u5DE5\u7A0B\u5E08\uFF0C\u5E73\u53F0\u6682\u65F6\u8FD8\u6CA1\u6709\u79EF\u5206\u7CFB\u7EDF\u3002Leader \u5E0C\u671B\u7531\u4F60\u6765\u8D1F\u8D23\u5F00\u53D1\u8FD9\u6837\u4E00\u4E2A\u7CFB\u7EDF\uFF0C\u4F60\u4F1A\u5982\u4F55\u6765\u505A\u5462\uFF1F</p><p>\u4F60\u53EF\u80FD\u4F1A\u8BF4\uFF0C\u53EA\u8981\u4EA7\u54C1\u7ECF\u7406\u7ED9\u6211\u4EA7\u54C1\u8BBE\u8BA1\u6587\u6863\uFF08PRD\uFF09\u3001\u7EBF\u6846\u56FE\uFF0C\u6211\u7167\u7740\u5B9E\u73B0\u5C31\u53EF\u4EE5\u4E86\u3002\u6211\u89C9\u5F97\uFF0C\u8FD9\u79CD\u60F3\u6CD5\u6709\u70B9\u72ED\u9698\u3002\u6211\u8BA4\u4E3A\uFF0C\u6280\u672F\u4EBA\u5458\u5E94\u8BE5\u66F4\u591A\u5730\u53C2\u4E0E\u5230\u4EA7\u54C1\u8BBE\u8BA1\u4E2D\u3002\u5728 Google \u5DE5\u4F5C\u7684\u65F6\u5019\uFF0C\u6211\u5F88\u660E\u663E\u80FD\u611F\u53D7\u5230\uFF0CGoogle \u5DE5\u7A0B\u5E08\u8DDF\u5176\u4ED6\u516C\u53F8\u5DE5\u7A0B\u5E08\u6709\u4E00\u4E2A\u5F88\u5927\u533A\u522B\uFF0C\u90A3\u5C31\u662F\u5927\u90E8\u5206\u4EBA\u90FD\u5177\u5907\u4EA7\u54C1\u601D\u7EF4\uFF0C\u5E76\u4E0D\u662F\u5B8C\u5168\u7684\u201C\u6280\u672F\u63A7\u201D\u3002\u6240\u4EE5\uFF0CGoogle \u5F88\u591A\u4EA7\u54C1\u7684\u521D\u671F\u8BBE\u8BA1\u90FD\u662F\u5DE5\u7A0B\u5E08\u6765\u5B8C\u6210\u7684\uFF0C\u5728\u4EA7\u54C1\u53D1\u5C55\u58EE\u5927\u5230\u4E00\u5B9A\u7A0B\u5EA6\u7684\u65F6\u5019\uFF0C\u624D\u4F1A\u5F15\u5165\u4EA7\u54C1\u7ECF\u7406\u7684\u89D2\u8272\u3002</p><p>\u90A3\u4F60\u53EF\u80FD\u8981\u95EE\u4E86\uFF0C\u4F5C\u4E3A\u6280\u672F\u4EBA\uFF0C\u6211\u8BE5\u600E\u4E48\u505A\u4EA7\u54C1\u8BBE\u8BA1\u5462\uFF1F\u9996\u5148\uFF0C\u4E00\u5B9A\u4E0D\u8981\u81EA\u5DF1\u4E00\u4E2A\u4EBA\u95F7\u5934\u60F3\u3002\u4E00\u65B9\u9762\uFF0C\u8FD9\u6837\u505A\u5F88\u96BE\u60F3\u5168\u9762\u3002\u53E6\u4E00\u65B9\u9762\uFF0C\u4ECE\u96F6\u5F00\u59CB\u8BBE\u8BA1\u4E5F\u6BD4\u8F83\u6D6A\u8D39\u65F6\u95F4\u3002\u6240\u4EE5\uFF0C\u6211\u4EEC\u8981\u5B66\u4F1A\u201C\u501F\u9274\u201D\u3002\u7231\u56E0\u65AF\u5766\u8BF4\u8FC7\uFF0C\u201C\u521B\u9020\u7684\u4E00\u5927\u79D8\u8BC0\u662F\u8981\u61C2\u5F97\u5982\u4F55\u9690\u85CF\u4F60\u7684\u6765\u6E90\u201D\u3002\u4F60\u770B\u5927\u5E08\u90FD\u542B\u84C4\u5730\u8868\u8FBE\u4E86\u201C\u501F\u9274\u201D\u7684\u91CD\u8981\u6027\uFF0C\u6211\u4EEC\u4E5F\u6CA1\u6709\u5FC5\u8981\u56E0\u4E3A\u201C\u501F\u9274\u201D\u800C\u611F\u5230\u4E0D\u597D\u610F\u601D\u4E86\u3002</p><p>\u6211\u4EEC\u53EF\u4EE5\u627E\u51E0\u4E2A\u7C7B\u4F3C\u7684\u4EA7\u54C1\uFF0C\u6BD4\u5982\u6DD8\u5B9D\uFF0C\u770B\u770B\u5B83\u4EEC\u662F\u5982\u4F55\u8BBE\u8BA1\u79EF\u5206\u7CFB\u7EDF\u7684\uFF0C\u7136\u540E\u501F\u9274\u5230\u6211\u4EEC\u7684\u4EA7\u54C1\u4E2D\u3002\u4F60\u53EF\u4EE5\u81EA\u5DF1\u4EB2\u81EA\u7528\u7528\u6DD8\u5B9D\uFF0C\u770B\u770B\u79EF\u5206\u662F\u600E\u4E48\u4F7F\u7528\u7684\uFF0C\u4E5F\u53EF\u4EE5\u76F4\u63A5\u767E\u5EA6\u4E00\u4E0B\u201C\u6DD8\u5B9D\u79EF\u5206\u89C4\u5219\u201D\u3002\u57FA\u4E8E\u8FD9\u4E24\u4E2A\u8F93\u5165\uFF0C\u6211\u4EEC\u57FA\u672C\u4E0A\u5C31\u5927\u81F4\u80FD\u6478\u6E05\u695A\u79EF\u5206\u7CFB\u7EDF\u8BE5\u5982\u4F55\u8BBE\u8BA1\u4E86\u3002\u9664\u6B64\u4E4B\u5916\uFF0C\u6211\u4EEC\u8FD8\u8981\u5145\u5206\u4E86\u89E3\u81EA\u5DF1\u516C\u53F8\u7684\u4EA7\u54C1\uFF0C\u5C06\u501F\u9274\u6765\u7684\u4E1C\u897F\u7CC5\u5408\u5728\u6211\u4EEC\u81EA\u5DF1\u7684\u4EA7\u54C1\u4E2D\uFF0C\u5E76\u505A\u9002\u5F53\u7684\u5FAE\u521B\u65B0\u3002</p><p>\u7B3C\u7EDF\u5730\u6765\u8BB2\uFF0C\u79EF\u5206\u7CFB\u7EDF\u65E0\u5916\u4E4E\u5C31\u4E24\u4E2A\u5927\u7684\u529F\u80FD\u70B9\uFF0C\u4E00\u4E2A\u662F\u8D5A\u53D6\u79EF\u5206\uFF0C\u53E6\u4E00\u4E2A\u662F\u6D88\u8D39\u79EF\u5206\u3002\u8D5A\u53D6\u79EF\u5206\u529F\u80FD\u5305\u62EC\u79EF\u5206\u8D5A\u53D6\u6E20\u9053\uFF0C\u6BD4\u5982\u4E0B\u8BA2\u5355\u3001\u6BCF\u65E5\u7B7E\u5230\u3001\u8BC4\u8BBA\u7B49\uFF1B\u8FD8\u5305\u62EC\u79EF\u5206\u5151\u6362\u89C4\u5219\uFF0C\u6BD4\u5982\u8BA2\u5355\u91D1\u989D\u4E0E\u79EF\u5206\u7684\u5151\u6362\u6BD4\u4F8B\uFF0C\u6BCF\u65E5\u7B7E\u5230\u8D60\u9001\u591A\u5C11\u79EF\u5206\u7B49\u3002\u6D88\u8D39\u79EF\u5206\u529F\u80FD\u5305\u62EC\u79EF\u5206\u6D88\u8D39\u6E20\u9053\uFF0C\u6BD4\u5982\u62B5\u6263\u8BA2\u5355\u91D1\u989D\u3001\u5151\u6362\u4F18\u60E0\u5238\u3001\u79EF\u5206\u6362\u8D2D\u3001\u53C2\u4E0E\u6D3B\u52A8\u6263\u79EF\u5206\u7B49\uFF1B\u8FD8\u5305\u62EC\u79EF\u5206\u5151\u6362\u89C4\u5219\uFF0C\u6BD4\u5982\u591A\u5C11\u79EF\u5206\u53EF\u4EE5\u6362\u7B97\u6210\u62B5\u6263\u8BA2\u5355\u7684\u591A\u5C11\u91D1\u989D\uFF0C\u4E00\u5F20\u4F18\u60E0\u5238\u9700\u8981\u591A\u5C11\u79EF\u5206\u6765\u5151\u6362\u7B49\u7B49\u3002</p><p>\u6211\u521A\u521A\u7ED9\u51FA\u7684\u53EA\u662F\u975E\u5E38\u7B3C\u7EDF\u3001\u7C97\u7CD9\u7684\u529F\u80FD\u9700\u6C42\u3002\u5728\u5B9E\u9645\u60C5\u51B5\u4E2D\uFF0C\u80AF\u5B9A\u8FD8\u6709\u4E00\u4E9B\u4E1A\u52A1\u7EC6\u8282\u9700\u8981\u8003\u8651\uFF0C\u6BD4\u5982\u79EF\u5206\u7684\u6709\u6548\u671F\u95EE\u9898\u3002\u5BF9\u4E8E\u8FD9\u4E9B\u4E1A\u52A1\u7EC6\u8282\uFF0C\u8FD8\u662F\u90A3\u53E5\u8BDD\uFF0C\u95F7\u5934\u62CD\u8111\u888B\u60F3\u662F\u60F3\u4E0D\u5168\u9762\u7684\u3002\u4EE5\u9632\u9057\u6F0F\uFF0C\u6211\u4EEC\u8FD8\u662F\u8981\u6709\u65B9\u6CD5\u53EF\u5BFB\u3002\u90A3\u9664\u4E86\u521A\u521A\u8BB2\u7684\u201C\u501F\u9274\u201D\u7684\u601D\u8DEF\u4E4B\u5916\uFF0C\u6211\u8FD8\u559C\u6B22\u901A\u8FC7\u4EA7\u54C1\u7684<strong>\u7EBF\u6846\u56FE</strong>\u3001<strong>\u7528\u6237\u7528\u4F8B</strong>\uFF08user case \uFF09\u6216\u8005\u53EB\u7528\u6237\u6545\u4E8B\uFF08user story\uFF09\u6765\u7EC6\u5316\u4E1A\u52A1\u6D41\u7A0B\uFF0C\u6316\u6398\u4E00\u4E9B\u6BD4\u8F83\u7EC6\u8282\u7684\u3001\u4E0D\u5BB9\u6613\u60F3\u5230\u7684\u529F\u80FD\u70B9\u3002</p><p>\u7EBF\u6846\u56FE\u5BF9\u4F60\u6765\u8BF4\u5E94\u8BE5\u4E0D\u964C\u751F\uFF0C\u6211\u5C31\u4E0D\u8D58\u8FF0\u4E86\uFF0C\u6211\u8FD9\u91CC\u91CD\u70B9\u8BF4\u4E00\u4E0B\u7528\u6237\u7528\u4F8B\u3002\u7528\u6237\u7528\u4F8B\u6709\u70B9\u513F\u7C7B\u4F3C\u6211\u4EEC\u540E\u9762\u8981\u8BB2\u7684\u5355\u5143\u6D4B\u8BD5\u7528\u4F8B\u3002\u5B83\u4FA7\u91CD\u60C5\u666F\u5316\uFF0C\u5176\u5B9E\u5C31\u662F\u6A21\u62DF\u7528\u6237\u5982\u4F55\u4F7F\u7528\u6211\u4EEC\u7684\u4EA7\u54C1\uFF0C\u63CF\u8FF0\u7528\u6237\u5728\u4E00\u4E2A\u7279\u5B9A\u7684\u5E94\u7528\u573A\u666F\u91CC\u7684\u4E00\u4E2A\u5B8C\u6574\u7684\u4E1A\u52A1\u64CD\u4F5C\u6D41\u7A0B\u3002\u6240\u4EE5\uFF0C\u5B83\u5305\u542B\u66F4\u591A\u7684\u7EC6\u8282\uFF0C\u4E14\u66F4\u52A0\u5BB9\u6613\u88AB\u4EBA\u7406\u89E3\u3002\u6BD4\u5982\uFF0C\u6709\u5173\u79EF\u5206\u6709\u6548\u671F\u7684\u7528\u6237\u7528\u4F8B\uFF0C\u6211\u4EEC\u53EF\u4EE5\u8FDB\u884C\u5982\u4E0B\u7684\u8BBE\u8BA1\uFF1A</p><ul><li><p>\u7528\u6237\u5728\u83B7\u53D6\u79EF\u5206\u7684\u65F6\u5019\uFF0C\u4F1A\u544A\u77E5\u79EF\u5206\u7684\u6709\u6548\u671F\uFF1B</p></li><li><p>\u7528\u6237\u5728\u4F7F\u7528\u79EF\u5206\u7684\u65F6\u5019\uFF0C\u4F1A\u4F18\u5148\u4F7F\u7528\u5FEB\u8FC7\u671F\u7684\u79EF\u5206\uFF1B</p></li><li><p>\u7528\u6237\u5728\u67E5\u8BE2\u79EF\u5206\u660E\u7EC6\u7684\u65F6\u5019\uFF0C\u4F1A\u663E\u793A\u79EF\u5206\u7684\u6709\u6548\u671F\u548C\u72B6\u6001\uFF08\u662F\u5426\u8FC7\u671F\uFF09\uFF1B</p></li><li><p>\u7528\u6237\u5728\u67E5\u8BE2\u603B\u53EF\u7528\u79EF\u5206\u7684\u65F6\u5019\uFF0C\u4F1A\u6392\u9664\u6389\u8FC7\u671F\u7684\u79EF\u5206\u3002</p></li></ul><p>\u901A\u8FC7\u4E0A\u9762\u8BB2\u7684\u65B9\u6CD5\uFF0C\u6211\u4EEC\u5C31\u53EF\u4EE5\u5C06\u529F\u80FD\u9700\u6C42\u5927\u81F4\u5F04\u6E05\u695A\u4E86\u3002\u79EF\u5206\u7CFB\u7EDF\u7684\u9700\u6C42\u5B9E\u9645\u4E0A\u5E76\u4E0D\u590D\u6742\uFF0C\u6211\u603B\u7ED3\u7F57\u5217\u4E86\u4E00\u4E0B\uFF0C\u5982\u4E0B\u6240\u793A\u3002</p><h3 id="_1-\u79EF\u5206\u8D5A\u53D6\u548C\u5151\u6362\u89C4\u5219" tabindex="-1"><a class="header-anchor" href="#_1-\u79EF\u5206\u8D5A\u53D6\u548C\u5151\u6362\u89C4\u5219" aria-hidden="true">#</a> 1. \u79EF\u5206\u8D5A\u53D6\u548C\u5151\u6362\u89C4\u5219</h3><p>\u79EF\u5206\u7684\u8D5A\u53D6\u6E20\u9053\u5305\u62EC\uFF1A\u4E0B\u8BA2\u5355\u3001\u6BCF\u65E5\u7B7E\u5230\u3001\u8BC4\u8BBA\u7B49\u3002</p><p>\u79EF\u5206\u5151\u6362\u89C4\u5219\u53EF\u4EE5\u662F\u6BD4\u8F83\u901A\u7528\u7684\u3002\u6BD4\u5982\uFF0C\u7B7E\u5230\u9001 10 \u79EF\u5206\u3002\u518D\u6BD4\u5982\uFF0C\u6309\u7167\u8BA2\u5355\u603B\u91D1\u989D\u7684 10% \u5151\u6362\u6210\u79EF\u5206\uFF0C\u4E5F\u5C31\u662F 100 \u5757\u94B1\u7684\u8BA2\u5355\u53EF\u4EE5\u79EF\u7D2F 10 \u79EF\u5206\u3002\u9664\u6B64\u4E4B\u5916\uFF0C\u79EF\u5206\u5151\u6362\u89C4\u5219\u4E5F\u53EF\u4EE5\u662F\u6BD4\u8F83\u7EC6\u5316\u7684\u3002\u6BD4\u5982\uFF0C\u4E0D\u540C\u7684\u5E97\u94FA\u3001\u4E0D\u540C\u7684\u5546\u54C1\uFF0C\u53EF\u4EE5\u8BBE\u7F6E\u4E0D\u540C\u7684\u79EF\u5206\u5151\u6362\u6BD4\u4F8B\u3002</p><p>\u5BF9\u4E8E\u79EF\u5206\u7684\u6709\u6548\u671F\uFF0C\u6211\u4EEC\u53EF\u4EE5\u6839\u636E\u4E0D\u540C\u6E20\u9053\uFF0C\u8BBE\u7F6E\u4E0D\u540C\u7684\u6709\u6548\u671F\u3002\u79EF\u5206\u5230\u671F\u4E4B\u540E\u4F1A\u4F5C\u5E9F\uFF1B\u5728\u6D88\u8D39\u79EF\u5206\u7684\u65F6\u5019\uFF0C\u4F18\u5148\u4F7F\u7528\u5FEB\u5230\u671F\u7684\u79EF\u5206\u3002</p><h3 id="_2-\u79EF\u5206\u6D88\u8D39\u548C\u5151\u6362\u89C4\u5219" tabindex="-1"><a class="header-anchor" href="#_2-\u79EF\u5206\u6D88\u8D39\u548C\u5151\u6362\u89C4\u5219" aria-hidden="true">#</a> 2. \u79EF\u5206\u6D88\u8D39\u548C\u5151\u6362\u89C4\u5219</h3><p>\u79EF\u5206\u7684\u6D88\u8D39\u6E20\u9053\u5305\u62EC\uFF1A\u62B5\u6263\u8BA2\u5355\u91D1\u989D\u3001\u5151\u6362\u4F18\u60E0\u5238\u3001\u79EF\u5206\u6362\u8D2D\u3001\u53C2\u4E0E\u6D3B\u52A8\u6263\u79EF\u5206\u7B49\u3002</p><p>\u6211\u4EEC\u53EF\u4EE5\u6839\u636E\u4E0D\u540C\u7684\u6D88\u8D39\u6E20\u9053\uFF0C\u8BBE\u7F6E\u4E0D\u540C\u7684\u79EF\u5206\u5151\u6362\u89C4\u5219\u3002\u6BD4\u5982\uFF0C\u79EF\u5206\u6362\u7B97\u6210\u6D88\u8D39\u62B5\u6263\u91D1\u989D\u7684\u6BD4\u4F8B\u662F 10%\uFF0C\u4E5F\u5C31\u662F 10 \u79EF\u5206\u53EF\u4EE5\u62B5\u6263 1 \u5757\u94B1\uFF1B100 \u79EF\u5206\u53EF\u4EE5\u5151\u6362 15 \u5757\u94B1\u7684\u4F18\u60E0\u5238\u7B49\u3002</p><h3 id="_3-\u79EF\u5206\u53CA\u5176\u660E\u7EC6\u67E5\u8BE2" tabindex="-1"><a class="header-anchor" href="#_3-\u79EF\u5206\u53CA\u5176\u660E\u7EC6\u67E5\u8BE2" aria-hidden="true">#</a> 3. \u79EF\u5206\u53CA\u5176\u660E\u7EC6\u67E5\u8BE2</h3><p>\u67E5\u8BE2\u7528\u6237\u7684\u603B\u79EF\u5206\uFF0C\u4EE5\u53CA\u8D5A\u53D6\u79EF\u5206\u548C\u6D88\u8D39\u79EF\u5206\u7684\u5386\u53F2\u8BB0\u5F55\u3002</p><h2 id="\u7CFB\u7EDF\u8BBE\u8BA1" tabindex="-1"><a class="header-anchor" href="#\u7CFB\u7EDF\u8BBE\u8BA1" aria-hidden="true">#</a> \u7CFB\u7EDF\u8BBE\u8BA1</h2><p>\u9762\u5411\u5BF9\u8C61\u8BBE\u8BA1\u805A\u7126\u5728\u4EE3\u7801\u5C42\u9762\uFF08\u4E3B\u8981\u662F\u9488\u5BF9\u7C7B\uFF09\uFF0C\u90A3\u7CFB\u7EDF\u8BBE\u8BA1\u5C31\u662F\u805A\u7126\u5728\u67B6\u6784\u5C42\u9762\uFF08\u4E3B\u8981\u662F\u9488\u5BF9\u6A21\u5757\uFF09\uFF0C\u4E24\u8005\u6709\u5F88\u591A\u76F8\u4F3C\u4E4B\u5904\u3002\u5F88\u591A\u8BBE\u8BA1\u539F\u5219\u548C\u601D\u60F3\u4E0D\u4EC5\u4EC5\u53EF\u4EE5\u5E94\u7528\u5230\u4EE3\u7801\u8BBE\u8BA1\u4E2D\uFF0C\u8FD8\u80FD\u7528\u5230\u67B6\u6784\u8BBE\u8BA1\u4E2D\u3002\u8FD8\u8BB0\u5F97\u9762\u5411\u5BF9\u8C61\u8BBE\u8BA1\u7684\u56DB\u4E2A\u6B65\u9AA4\u5417\uFF1F\u5B9E\u9645\u4E0A\uFF0C\u6211\u4EEC\u4E5F\u53EF\u4EE5\u501F\u9274\u90A3\u4E2A\u8FC7\u7A0B\u6765\u505A\u7CFB\u7EDF\u8BBE\u8BA1\u3002</p><h3 id="_1-\u5408\u7406\u5730\u5C06\u529F\u80FD\u5212\u5206\u5230\u4E0D\u540C\u6A21\u5757" tabindex="-1"><a class="header-anchor" href="#_1-\u5408\u7406\u5730\u5C06\u529F\u80FD\u5212\u5206\u5230\u4E0D\u540C\u6A21\u5757" aria-hidden="true">#</a> 1. \u5408\u7406\u5730\u5C06\u529F\u80FD\u5212\u5206\u5230\u4E0D\u540C\u6A21\u5757</h3><p>\u524D\u9762\u8BB2\u5230\u9762\u5411\u5BF9\u8C61\u8BBE\u8BA1\u7684\u65F6\u5019\uFF0C\u6211\u4EEC\u63D0\u5230\uFF0C\u9762\u5411\u5BF9\u8C61\u8BBE\u8BA1\u7684\u672C\u8D28\u5C31\u662F\u628A\u5408\u9002\u7684\u4EE3\u7801\u653E\u5230\u5408\u9002\u7684\u7C7B\u4E2D\u3002\u5408\u7406\u5730\u5212\u5206\u4EE3\u7801\u53EF\u4EE5\u5B9E\u73B0\u4EE3\u7801\u7684\u9AD8\u5185\u805A\u3001\u4F4E\u8026\u5408\uFF0C\u7C7B\u4E0E\u7C7B\u4E4B\u95F4\u7684\u4EA4\u4E92\u7B80\u5355\u6E05\u6670\uFF0C\u4EE3\u7801\u6574\u4F53\u7ED3\u6784\u4E00\u76EE\u4E86\u7136\uFF0C\u90A3\u4EE3\u7801\u7684\u8D28\u91CF\u5C31\u4E0D\u4F1A\u5DEE\u5230\u54EA\u91CC\u53BB\u3002\u7C7B\u6BD4\u9762\u5411\u5BF9\u8C61\u8BBE\u8BA1\uFF0C\u7CFB\u7EDF\u8BBE\u8BA1\u5B9E\u9645\u4E0A\u5C31\u662F\u5C06\u5408\u9002\u7684\u529F\u80FD\u653E\u5230\u5408\u9002\u7684\u6A21\u5757\u4E2D\u3002\u5408\u7406\u5730\u5212\u5206\u6A21\u5757\u4E5F\u53EF\u4EE5\u505A\u5230\u6A21\u5757\u5C42\u9762\u7684\u9AD8\u5185\u805A\u3001\u4F4E\u8026\u5408\uFF0C\u67B6\u6784\u6574\u6D01\u6E05\u6670\u3002</p><p>\u5BF9\u4E8E\u524D\u9762\u7F57\u5217\u7684\u6240\u6709\u529F\u80FD\u70B9\uFF0C\u6211\u4EEC\u6709\u4E0B\u9762\u4E09\u79CD\u6A21\u5757\u5212\u5206\u65B9\u6CD5\u3002</p><p>\u7B2C\u4E00\u79CD\u5212\u5206\u65B9\u5F0F\u662F\uFF1A\u79EF\u5206\u8D5A\u53D6\u6E20\u9053\u53CA\u5151\u6362\u89C4\u5219\u3001\u6D88\u8D39\u6E20\u9053\u53CA\u5151\u6362\u89C4\u5219\u7684\u7BA1\u7406\u548C\u7EF4\u62A4\uFF08\u589E\u5220\u6539\u67E5\uFF09\uFF0C\u4E0D\u5212\u5206\u5230\u79EF\u5206\u7CFB\u7EDF\u4E2D\uFF0C\u800C\u662F\u653E\u5230\u66F4\u4E0A\u5C42\u7684\u8425\u9500\u7CFB\u7EDF\u4E2D\u3002\u8FD9\u6837\u79EF\u5206\u7CFB\u7EDF\u5C31\u4F1A\u53D8\u5F97\u975E\u5E38\u7B80\u5355\uFF0C\u53EA\u9700\u8981\u8D1F\u8D23\u589E\u52A0\u79EF\u5206\u3001\u51CF\u5C11\u79EF\u5206\u3001\u67E5\u8BE2\u79EF\u5206\u3001\u67E5\u8BE2\u79EF\u5206\u660E\u7EC6\u7B49\u8FD9\u51E0\u4E2A\u5DE5\u4F5C\u3002</p><p>\u6211\u4E3E\u4E2A\u4F8B\u5B50\u89E3\u91CA\u4E00\u4E0B\u3002\u6BD4\u5982\uFF0C\u7528\u6237\u901A\u8FC7\u4E0B\u8BA2\u5355\u8D5A\u53D6\u79EF\u5206\u3002\u8BA2\u5355\u7CFB\u7EDF\u901A\u8FC7\u5F02\u6B65\u53D1\u9001\u6D88\u606F\u6216\u8005\u540C\u6B65\u8C03\u7528\u63A5\u53E3\u7684\u65B9\u5F0F\uFF0C\u544A\u77E5\u8425\u9500\u7CFB\u7EDF\u8BA2\u5355\u4EA4\u6613\u6210\u529F\u3002\u8425\u9500\u7CFB\u7EDF\u6839\u636E\u62FF\u5230\u7684\u8BA2\u5355\u4FE1\u606F\uFF0C\u67E5\u8BE2\u8BA2\u5355\u5BF9\u5E94\u7684\u79EF\u5206\u5151\u6362\u89C4\u5219\uFF08\u5151\u6362\u6BD4\u4F8B\u3001\u6709\u6548\u671F\u7B49\uFF09\uFF0C\u8BA1\u7B97\u5F97\u5230\u8BA2\u5355\u53EF\u5151\u6362\u7684\u79EF\u5206\u6570\u91CF\uFF0C\u7136\u540E\u8C03\u7528\u79EF\u5206\u7CFB\u7EDF\u7684\u63A5\u53E3\u7ED9\u7528\u6237\u589E\u52A0\u79EF\u5206\u3002</p><p>\u7B2C\u4E8C\u79CD\u5212\u5206\u65B9\u5F0F\u662F\uFF1A\u79EF\u5206\u8D5A\u53D6\u6E20\u9053\u53CA\u5151\u6362\u89C4\u5219\u3001\u6D88\u8D39\u6E20\u9053\u53CA\u5151\u6362\u89C4\u5219\u7684\u7BA1\u7406\u548C\u7EF4\u62A4\uFF0C\u5206\u6563\u5728\u5404\u4E2A\u76F8\u5173\u4E1A\u52A1\u7CFB\u7EDF\u4E2D\uFF0C\u6BD4\u5982\u8BA2\u5355\u7CFB\u7EDF\u3001\u8BC4\u8BBA\u7CFB\u7EDF\u3001\u7B7E\u5230\u7CFB\u7EDF\u3001\u6362\u8D2D\u5546\u57CE\u3001\u4F18\u60E0\u5238\u7CFB\u7EDF\u7B49\u3002\u8FD8\u662F\u521A\u521A\u90A3\u4E2A\u4E0B\u8BA2\u5355\u8D5A\u53D6\u79EF\u5206\u7684\u4F8B\u5B50\uFF0C\u5728\u8FD9\u79CD\u60C5\u51B5\u4E0B\uFF0C\u7528\u6237\u4E0B\u8BA2\u5355\u6210\u529F\u4E4B\u540E\uFF0C\u8BA2\u5355\u7CFB\u7EDF\u6839\u636E\u5546\u54C1\u5BF9\u5E94\u7684\u79EF\u5206\u5151\u6362\u6BD4\u4F8B\uFF0C\u8BA1\u7B97\u6240\u80FD\u5151\u6362\u7684\u79EF\u5206\u6570\u91CF\uFF0C\u7136\u540E\u76F4\u63A5\u8C03\u7528\u79EF\u5206\u7CFB\u7EDF\u7ED9\u7528\u6237\u589E\u52A0\u79EF\u5206\u3002</p><p>\u7B2C\u4E09\u79CD\u5212\u5206\u65B9\u5F0F\u662F\uFF1A\u6240\u6709\u7684\u529F\u80FD\u90FD\u5212\u5206\u5230\u79EF\u5206\u7CFB\u7EDF\u4E2D\uFF0C\u5305\u62EC\u79EF\u5206\u8D5A\u53D6\u6E20\u9053\u53CA\u5151\u6362\u89C4\u5219\u3001\u6D88\u8D39\u6E20\u9053\u53CA\u5151\u6362\u89C4\u5219\u7684\u7BA1\u7406\u548C\u7EF4\u62A4\u3002\u8FD8\u662F\u540C\u6837\u7684\u4F8B\u5B50\uFF0C\u7528\u6237\u4E0B\u8BA2\u5355\u6210\u529F\u4E4B\u540E\uFF0C\u8BA2\u5355\u7CFB\u7EDF\u76F4\u63A5\u544A\u77E5\u79EF\u5206\u7CFB\u7EDF\u8BA2\u5355\u4EA4\u6613\u6210\u529F\uFF0C\u79EF\u5206\u7CFB\u7EDF\u6839\u636E\u8BA2\u5355\u4FE1\u606F\u67E5\u8BE2\u79EF\u5206\u5151\u6362\u89C4\u5219\uFF0C\u7ED9\u7528\u6237\u589E\u52A0\u79EF\u5206\u3002</p><p>\u600E\u4E48\u5224\u65AD\u54EA\u79CD\u6A21\u5757\u5212\u5206\u5408\u7406\u5462\uFF1F\u5B9E\u9645\u4E0A\uFF0C\u6211\u4EEC\u53EF\u4EE5\u53CD\u8FC7\u6765\u901A\u8FC7\u770B\u5B83\u662F\u5426\u7B26\u5408\u9AD8\u5185\u805A\u3001\u4F4E\u8026\u5408\u7279\u6027\u6765\u5224\u65AD\u3002\u5982\u679C\u4E00\u4E2A\u529F\u80FD\u7684\u4FEE\u6539\u6216\u6DFB\u52A0\uFF0C\u7ECF\u5E38\u8981\u8DE8\u56E2\u961F\u3001\u8DE8\u9879\u76EE\u3001\u8DE8\u7CFB\u7EDF\u624D\u80FD\u5B8C\u6210\uFF0C\u90A3\u8BF4\u660E\u6A21\u5757\u5212\u5206\u7684\u4E0D\u591F\u5408\u7406\uFF0C\u804C\u8D23\u4E0D\u591F\u6E05\u6670\uFF0C\u8026\u5408\u8FC7\u4E8E\u4E25\u91CD\u3002</p><p>\u9664\u6B64\u4E4B\u5916\uFF0C\u4E3A\u4E86\u907F\u514D\u4E1A\u52A1\u77E5\u8BC6\u7684\u8026\u5408\uFF0C\u8BA9\u4E0B\u5C42\u7CFB\u7EDF\u66F4\u52A0\u901A\u7528\uFF0C\u4E00\u822C\u6765\u8BB2\uFF0C\u6211\u4EEC\u4E0D\u5E0C\u671B\u4E0B\u5C42\u7CFB\u7EDF\uFF08\u4E5F\u5C31\u662F\u88AB\u8C03\u7528\u7684\u7CFB\u7EDF\uFF09\u5305\u542B\u592A\u591A\u4E0A\u5C42\u7CFB\u7EDF\uFF08\u4E5F\u5C31\u662F\u8C03\u7528\u7CFB\u7EDF\uFF09\u7684\u4E1A\u52A1\u4FE1\u606F\uFF0C\u4F46\u662F\uFF0C\u53EF\u4EE5\u63A5\u53D7\u4E0A\u5C42\u7CFB\u7EDF\u5305\u542B\u4E0B\u5C42\u7CFB\u7EDF\u7684\u4E1A\u52A1\u4FE1\u606F\u3002\u6BD4\u5982\uFF0C\u8BA2\u5355\u7CFB\u7EDF\u3001\u4F18\u60E0\u5238\u7CFB\u7EDF\u3001\u6362\u8D2D\u5546\u57CE\u7B49\u4F5C\u4E3A\u8C03\u7528\u79EF\u5206\u7CFB\u7EDF\u7684\u4E0A\u5C42\u7CFB\u7EDF\uFF0C\u53EF\u4EE5\u5305\u542B\u4E00\u4E9B\u79EF\u5206\u76F8\u5173\u7684\u4E1A\u52A1\u4FE1\u606F\u3002\u4F46\u662F\uFF0C\u53CD\u8FC7\u6765\uFF0C\u79EF\u5206\u7CFB\u7EDF\u4E2D\u6700\u597D\u4E0D\u8981\u5305\u542B\u592A\u591A\u8DDF\u8BA2\u5355\u3001\u4F18\u60E0\u5238\u3001\u6362\u8D2D\u7B49\u76F8\u5173\u7684\u4FE1\u606F\u3002</p><p>\u6240\u4EE5\uFF0C\u7EFC\u5408\u8003\u8651\uFF0C\u6211\u4EEC\u66F4\u503E\u5411\u4E8E\u7B2C\u4E00\u79CD\u548C\u7B2C\u4E8C\u79CD\u6A21\u5757\u5212\u5206\u65B9\u5F0F\u3002\u4F46\u662F\uFF0C\u4E0D\u7BA1\u9009\u62E9\u8FD9\u4E24\u79CD\u4E2D\u7684\u54EA\u4E00\u79CD\uFF0C\u79EF\u5206\u7CFB\u7EDF\u6240\u8D1F\u8D23\u7684\u5DE5\u4F5C\u662F\u4E00\u6837\u7684\uFF0C\u53EA\u5305\u542B\u79EF\u5206\u7684\u589E\u3001\u51CF\u3001\u67E5\u8BE2\uFF0C\u4EE5\u53CA\u79EF\u5206\u660E\u7EC6\u7684\u8BB0\u5F55\u548C\u67E5\u8BE2\u3002</p><h3 id="_2-\u8BBE\u8BA1\u6A21\u5757\u4E0E\u6A21\u5757\u4E4B\u95F4\u7684\u4EA4\u4E92\u5173\u7CFB" tabindex="-1"><a class="header-anchor" href="#_2-\u8BBE\u8BA1\u6A21\u5757\u4E0E\u6A21\u5757\u4E4B\u95F4\u7684\u4EA4\u4E92\u5173\u7CFB" aria-hidden="true">#</a> 2. \u8BBE\u8BA1\u6A21\u5757\u4E0E\u6A21\u5757\u4E4B\u95F4\u7684\u4EA4\u4E92\u5173\u7CFB</h3><p>\u5728\u9762\u5411\u5BF9\u8C61\u8BBE\u8BA1\u4E2D\uFF0C\u7C7B\u8BBE\u8BA1\u597D\u4E4B\u540E\uFF0C\u6211\u4EEC\u9700\u8981\u8BBE\u8BA1\u7C7B\u4E4B\u95F4\u7684\u4EA4\u4E92\u5173\u7CFB\u3002\u7C7B\u6BD4\u5230\u7CFB\u7EDF\u8BBE\u8BA1\uFF0C\u7CFB\u7EDF\u804C\u8D23\u5212\u5206\u597D\u4E4B\u540E\uFF0C\u63A5\u4E0B\u6765\u5C31\u662F\u8BBE\u8BA1\u7CFB\u7EDF\u4E4B\u95F4\u7684\u4EA4\u4E92\uFF0C\u4E5F\u5C31\u662F\u786E\u5B9A\u6709\u54EA\u4E9B\u7CFB\u7EDF\u8DDF\u79EF\u5206\u7CFB\u7EDF\u4E4B\u95F4\u6709\u4EA4\u4E92\u4EE5\u53CA\u5982\u4F55\u8FDB\u884C\u4EA4\u4E92\u3002</p><p>\u6BD4\u8F83\u5E38\u89C1\u7684\u7CFB\u7EDF\u4E4B\u95F4\u7684\u4EA4\u4E92\u65B9\u5F0F\u6709\u4E24\u79CD\uFF0C\u4E00\u79CD\u662F\u540C\u6B65\u63A5\u53E3\u8C03\u7528\uFF0C\u53E6\u4E00\u79CD\u662F\u5229\u7528\u6D88\u606F\u4E2D\u95F4\u4EF6\u5F02\u6B65\u8C03\u7528\u3002\u7B2C\u4E00\u79CD\u65B9\u5F0F\u7B80\u5355\u76F4\u63A5\uFF0C\u7B2C\u4E8C\u79CD\u65B9\u5F0F\u7684\u89E3\u8026\u6548\u679C\u66F4\u597D\u3002</p><p>\u6BD4\u5982\uFF0C\u7528\u6237\u4E0B\u8BA2\u5355\u6210\u529F\u4E4B\u540E\uFF0C\u8BA2\u5355\u7CFB\u7EDF\u63A8\u9001\u4E00\u6761\u6D88\u606F\u5230\u6D88\u606F\u4E2D\u95F4\u4EF6\uFF0C\u8425\u9500\u7CFB\u7EDF\u8BA2\u9605\u8BA2\u5355\u6210\u529F\u6D88\u606F\uFF0C\u89E6\u53D1\u6267\u884C\u76F8\u5E94\u7684\u79EF\u5206\u5151\u6362\u903B\u8F91\u3002\u8FD9\u6837\u8BA2\u5355\u7CFB\u7EDF\u5C31\u8DDF\u8425\u9500\u7CFB\u7EDF\u5B8C\u5168\u89E3\u8026\uFF0C\u8BA2\u5355\u7CFB\u7EDF\u4E0D\u9700\u8981\u77E5\u9053\u4EFB\u4F55\u8DDF\u79EF\u5206\u76F8\u5173\u7684\u903B\u8F91\uFF0C\u800C\u8425\u9500\u7CFB\u7EDF\u4E5F\u4E0D\u9700\u8981\u76F4\u63A5\u8DDF\u8BA2\u5355\u7CFB\u7EDF\u4EA4\u4E92\u3002</p><p>\u9664\u6B64\u4E4B\u5916\uFF0C\u4E0A\u4E0B\u5C42\u7CFB\u7EDF\u4E4B\u95F4\u7684\u8C03\u7528\u503E\u5411\u4E8E\u901A\u8FC7\u540C\u6B65\u63A5\u53E3\uFF0C\u540C\u5C42\u4E4B\u95F4\u7684\u8C03\u7528\u503E\u5411\u4E8E\u5F02\u6B65\u6D88\u606F\u8C03\u7528\u3002\u6BD4\u5982\uFF0C\u8425\u9500\u7CFB\u7EDF\u548C\u79EF\u5206\u7CFB\u7EDF\u662F\u4E0A\u4E0B\u5C42\u5173\u7CFB\uFF0C\u5B83\u4EEC\u4E4B\u95F4\u5C31\u6BD4\u8F83\u63A8\u8350\u4F7F\u7528\u540C\u6B65\u63A5\u53E3\u8C03\u7528\u3002</p><h3 id="_3-\u8BBE\u8BA1\u6A21\u5757\u7684\u63A5\u53E3\u3001\u6570\u636E\u5E93\u3001\u4E1A\u52A1\u6A21\u578B" tabindex="-1"><a class="header-anchor" href="#_3-\u8BBE\u8BA1\u6A21\u5757\u7684\u63A5\u53E3\u3001\u6570\u636E\u5E93\u3001\u4E1A\u52A1\u6A21\u578B" aria-hidden="true">#</a> 3. \u8BBE\u8BA1\u6A21\u5757\u7684\u63A5\u53E3\u3001\u6570\u636E\u5E93\u3001\u4E1A\u52A1\u6A21\u578B</h3><p>\u521A\u521A\u8BB2\u4E86\u6A21\u5757\u7684\u529F\u80FD\u5212\u5206\uFF0C\u6A21\u5757\u4E4B\u95F4\u7684\u4EA4\u4E92\u7684\u8BBE\u8BA1\uFF0C\u73B0\u5728\uFF0C\u6211\u4EEC\u518D\u6765\u770B\uFF0C\u6A21\u5757\u672C\u8EAB\u5982\u4F55\u6765\u8BBE\u8BA1\u3002\u5B9E\u9645\u4E0A\uFF0C\u4E1A\u52A1\u7CFB\u7EDF\u672C\u8EAB\u7684\u8BBE\u8BA1\u65E0\u5916\u4E4E\u6709\u8FD9\u6837\u4E09\u65B9\u9762\u7684\u5DE5\u4F5C\u8981\u505A\uFF1A\u63A5\u53E3\u8BBE\u8BA1\u3001\u6570\u636E\u5E93\u8BBE\u8BA1\u548C\u4E1A\u52A1\u6A21\u578B\u8BBE\u8BA1\u3002\u8FD9\u90E8\u5206\u7684\u5177\u4F53\u5185\u5BB9\u6211\u4EEC\u653E\u5230\u4E0B\u4E00\u4E0B\u8282\u8BFE\u4E2D\u8DDF\u5B9E\u73B0\u4E00\u5757\u8FDB\u884C\u8BB2\u89E3\u3002</p><h2 id="\u4E1A\u52A1\u5F00\u53D1\u5305\u62EC\u54EA\u4E9B\u5DE5\u4F5C" tabindex="-1"><a class="header-anchor" href="#\u4E1A\u52A1\u5F00\u53D1\u5305\u62EC\u54EA\u4E9B\u5DE5\u4F5C" aria-hidden="true">#</a> \u4E1A\u52A1\u5F00\u53D1\u5305\u62EC\u54EA\u4E9B\u5DE5\u4F5C\uFF1F</h2><p>\u5B9E\u9645\u4E0A\uFF0C\u6211\u4EEC\u5E73\u65F6\u505A\u4E1A\u52A1\u7CFB\u7EDF\u7684\u8BBE\u8BA1\u4E0E\u5F00\u53D1\uFF0C\u65E0\u5916\u4E4E\u6709\u8FD9\u6837\u4E09\u65B9\u9762\u7684\u5DE5\u4F5C\u8981\u505A\uFF1A\u63A5\u53E3\u8BBE\u8BA1\u3001\u6570\u636E\u5E93\u8BBE\u8BA1\u548C\u4E1A\u52A1\u6A21\u578B\u8BBE\u8BA1\uFF08\u4E5F\u5C31\u662F\u4E1A\u52A1\u903B\u8F91\uFF09\u3002</p><p>\u6570\u636E\u5E93\u548C\u63A5\u53E3\u7684\u8BBE\u8BA1\u975E\u5E38\u91CD\u8981\uFF0C\u4E00\u65E6\u8BBE\u8BA1\u597D\u5E76\u6295\u5165\u4F7F\u7528\u4E4B\u540E\uFF0C\u8FD9\u4E24\u90E8\u5206\u90FD\u4E0D\u80FD\u8F7B\u6613\u6539\u52A8\u3002\u6539\u52A8\u6570\u636E\u5E93\u8868\u7ED3\u6784\uFF0C\u9700\u8981\u6D89\u53CA\u6570\u636E\u7684\u8FC1\u79FB\u548C\u9002\u914D\uFF1B\u6539\u52A8\u63A5\u53E3\uFF0C\u9700\u8981\u63A8\u52A8\u63A5\u53E3\u7684\u4F7F\u7528\u8005\u4F5C\u76F8\u5E94\u7684\u4EE3\u7801\u4FEE\u6539\u3002\u8FD9\u4E24\u79CD\u60C5\u51B5\uFF0C\u5373\u4FBF\u662F\u5FAE\u5C0F\u7684\u6539\u52A8\uFF0C\u6267\u884C\u8D77\u6765\u90FD\u4F1A\u975E\u5E38\u9EBB\u70E6\u3002\u56E0\u6B64\uFF0C\u6211\u4EEC\u5728\u8BBE\u8BA1\u63A5\u53E3\u548C\u6570\u636E\u5E93\u7684\u65F6\u5019\uFF0C\u4E00\u5B9A\u8981\u591A\u82B1\u70B9\u5FC3\u601D\u548C\u65F6\u95F4\uFF0C\u5207\u4E0D\u53EF\u8FC7\u4E8E\u968F\u610F\u3002\u76F8\u53CD\uFF0C\u4E1A\u52A1\u903B\u8F91\u4EE3\u7801\u4FA7\u91CD\u5185\u90E8\u5B9E\u73B0\uFF0C\u4E0D\u6D89\u53CA\u88AB\u5916\u90E8\u4F9D\u8D56\u7684\u63A5\u53E3\uFF0C\u4E5F\u4E0D\u5305\u542B\u6301\u4E45\u5316\u7684\u6570\u636E\uFF0C\u6240\u4EE5\u5BF9\u6539\u52A8\u7684\u5BB9\u5FCD\u6027\u66F4\u5927\u3002</p><p><strong>\u9488\u5BF9\u79EF\u5206\u7CFB\u7EDF\uFF0C\u6211\u4EEC\u5148\u6765\u770B\uFF0C\u5982\u4F55\u8BBE\u8BA1\u6570\u636E\u5E93\u3002</strong></p><p>\u6570\u636E\u5E93\u7684\u8BBE\u8BA1\u6BD4\u8F83\u7B80\u5355\u3002\u5B9E\u9645\u4E0A\uFF0C\u6211\u4EEC\u53EA\u9700\u8981\u4E00\u5F20\u8BB0\u5F55\u79EF\u5206\u6D41\u6C34\u660E\u7EC6\u7684\u8868\u5C31\u53EF\u4EE5\u4E86\u3002\u8868\u4E2D\u8BB0\u5F55\u79EF\u5206\u7684\u8D5A\u53D6\u548C\u6D88\u8D39\u6D41\u6C34\u3002\u7528\u6237\u79EF\u5206\u7684\u5404\u79CD\u7EDF\u8BA1\u6570\u636E\uFF0C\u6BD4\u5982\u603B\u79EF\u5206\u3001\u603B\u53EF\u7528\u79EF\u5206\u7B49\uFF0C\u90FD\u53EF\u4EE5\u901A\u8FC7\u8FD9\u5F20\u8868\u6765\u8BA1\u7B97\u5F97\u5230\u3002</p><p><img src="https://personal-site-pictures.oss-cn-beijing.aliyuncs.com/img/image-20220612120235224.png" alt="image-20220612120235224" loading="lazy"></p><p><strong>\u63A5\u4E0B\u6765\uFF0C\u6211\u4EEC\u518D\u6765\u770B\uFF0C\u5982\u4F55\u8BBE\u8BA1\u79EF\u5206\u7CFB\u7EDF\u7684\u63A5\u53E3\u3002</strong></p><p>\u63A5\u53E3\u8BBE\u8BA1\u8981\u7B26\u5408\u5355\u4E00\u804C\u8D23\u539F\u5219\uFF0C\u7C92\u5EA6\u8D8A\u5C0F\u901A\u7528\u6027\u5C31\u8D8A\u597D\u3002\u4F46\u662F\uFF0C\u63A5\u53E3\u7C92\u5EA6\u592A\u5C0F\u4E5F\u4F1A\u5E26\u6765\u4E00\u4E9B\u95EE\u9898\u3002\u6BD4\u5982\uFF0C\u4E00\u4E2A\u529F\u80FD\u7684\u5B9E\u73B0\u8981\u8C03\u7528\u591A\u4E2A\u5C0F\u63A5\u53E3\uFF0C\u4E00\u65B9\u9762\u5982\u679C\u63A5\u53E3\u8C03\u7528\u8D70\u7F51\u7EDC\uFF08\u7279\u522B\u662F\u516C\u7F51\uFF09\uFF0C\u591A\u6B21\u8FDC\u7A0B\u63A5\u53E3\u8C03\u7528\u4F1A\u5F71\u54CD\u6027\u80FD\uFF1B\u53E6\u4E00\u65B9\u9762\uFF0C\u672C\u8BE5\u5728\u4E00\u4E2A\u63A5\u53E3\u4E2D\u5B8C\u6210\u7684\u539F\u5B50\u64CD\u4F5C\uFF0C\u73B0\u5728\u5206\u62C6\u6210\u591A\u4E2A\u5C0F\u63A5\u53E3\u6765\u5B8C\u6210\uFF0C\u5C31\u53EF\u80FD\u4F1A\u6D89\u53CA\u5206\u5E03\u5F0F\u4E8B\u52A1\u7684\u6570\u636E\u4E00\u81F4\u6027\u95EE\u9898\uFF08\u4E00\u4E2A\u63A5\u53E3\u6267\u884C\u6210\u529F\u4E86\uFF0C\u4F46\u53E6\u4E00\u4E2A\u63A5\u53E3\u6267\u884C\u5931\u8D25\u4E86\uFF09\u3002\u6240\u4EE5\uFF0C\u4E3A\u4E86\u517C\u987E\u6613\u7528\u6027\u548C\u6027\u80FD\uFF0C\u6211\u4EEC\u53EF\u4EE5\u501F\u9274 facade\uFF08\u5916\u89C2\uFF09\u8BBE\u8BA1\u6A21\u5F0F\uFF0C\u5728\u804C\u8D23\u5355\u4E00\u7684\u7EC6\u7C92\u5EA6\u63A5\u53E3\u4E4B\u4E0A\uFF0C\u518D\u5C01\u88C5\u4E00\u5C42\u7C97\u7C92\u5EA6\u7684\u63A5\u53E3\u7ED9\u5916\u90E8\u4F7F\u7528\u3002</p><p>\u5BF9\u4E8E\u79EF\u5206\u7CFB\u7EDF\u6765\u8BF4\uFF0C\u6211\u4EEC\u9700\u8981\u8BBE\u8BA1\u5982\u4E0B\u8FD9\u6837\u51E0\u4E2A\u63A5\u53E3\u3002</p><p><img src="https://personal-site-pictures.oss-cn-beijing.aliyuncs.com/img/image-20220612120302103.png" alt="image-20220612120302103" loading="lazy"></p><p><strong>\u6700\u540E\uFF0C\u6211\u4EEC\u6765\u770B\u4E1A\u52A1\u6A21\u578B\u7684\u8BBE\u8BA1\u3002</strong></p><p>\u524D\u9762\u6211\u4EEC\u8BB2\u5230\uFF0C\u4ECE\u4EE3\u7801\u5B9E\u73B0\u89D2\u5EA6\u6765\u8BF4\uFF0C\u5927\u90E8\u5206\u4E1A\u52A1\u7CFB\u7EDF\u7684\u5F00\u53D1\u90FD\u53EF\u4EE5\u5206\u4E3A Controller\u3001Service\u3001Repository \u4E09\u5C42\u3002Controller \u5C42\u8D1F\u8D23\u63A5\u53E3\u66B4\u9732\uFF0CRepository \u5C42\u8D1F\u8D23\u6570\u636E\u8BFB\u5199\uFF0CService \u5C42\u8D1F\u8D23\u6838\u5FC3\u4E1A\u52A1\u903B\u8F91\uFF0C\u4E5F\u5C31\u662F\u8FD9\u91CC\u8BF4\u7684\u4E1A\u52A1\u6A21\u578B\u3002</p><p>\u9664\u6B64\u4E4B\u5916\uFF0C\u524D\u9762\u6211\u4EEC\u8FD8\u63D0\u5230\u4E24\u79CD\u5F00\u53D1\u6A21\u5F0F\uFF0C\u57FA\u4E8E\u8D2B\u8840\u6A21\u578B\u7684\u4F20\u7EDF\u5F00\u53D1\u6A21\u5F0F\u548C\u57FA\u4E8E\u5145\u8840\u6A21\u578B\u7684 DDD \u5F00\u53D1\u6A21\u5F0F\u3002\u524D\u8005\u662F\u4E00\u79CD\u9762\u5411\u8FC7\u7A0B\u7684\u7F16\u7A0B\u98CE\u683C\uFF0C\u540E\u8005\u662F\u4E00\u79CD\u9762\u5411\u5BF9\u8C61\u7684\u7F16\u7A0B\u98CE\u683C\u3002\u4E0D\u7BA1\u662F DDD \u8FD8\u662F OOP\uFF0C\u9AD8\u7EA7\u5F00\u53D1\u6A21\u5F0F\u7684\u5B58\u5728\u4E00\u822C\u90FD\u662F\u4E3A\u4E86\u5E94\u5BF9\u590D\u6742\u7CFB\u7EDF\uFF0C\u5E94\u5BF9\u7CFB\u7EDF\u7684\u590D\u6742\u6027\u3002\u5BF9\u4E8E\u6211\u4EEC\u8981\u5F00\u53D1\u7684\u79EF\u5206\u7CFB\u7EDF\u6765\u8BF4\uFF0C\u56E0\u4E3A\u4E1A\u52A1\u76F8\u5BF9\u6BD4\u8F83\u7B80\u5355\uFF0C\u6240\u4EE5\uFF0C\u9009\u62E9\u7B80\u5355\u7684\u57FA\u4E8E\u8D2B\u8840\u6A21\u578B\u7684\u4F20\u7EDF\u5F00\u53D1\u6A21\u5F0F\u5C31\u8DB3\u591F\u4E86\u3002</p><p>\u4ECE\u5F00\u53D1\u7684\u89D2\u5EA6\u6765\u8BF4\uFF0C\u6211\u4EEC\u53EF\u4EE5\u628A\u79EF\u5206\u7CFB\u7EDF\u4F5C\u4E3A\u4E00\u4E2A\u72EC\u7ACB\u7684\u9879\u76EE\uFF0C\u6765\u72EC\u7ACB\u5F00\u53D1\uFF0C\u4E5F\u53EF\u4EE5\u8DDF\u5176\u4ED6\u4E1A\u52A1\u4EE3\u7801\uFF08\u6BD4\u5982\u8425\u9500\u7CFB\u7EDF\uFF09\u653E\u5230\u540C\u4E00\u4E2A\u9879\u76EE\u4E2D\u8FDB\u884C\u5F00\u53D1\u3002\u4ECE\u8FD0\u7EF4\u7684\u89D2\u5EA6\u6765\u8BF4\uFF0C\u6211\u4EEC\u53EF\u4EE5\u5C06\u5B83\u8DDF\u5176\u4ED6\u4E1A\u52A1\u4E00\u5757\u90E8\u7F72\uFF0C\u4E5F\u53EF\u4EE5\u4F5C\u4E3A\u4E00\u4E2A\u5FAE\u670D\u52A1\u72EC\u7ACB\u90E8\u7F72\u3002\u5177\u4F53\u9009\u62E9\u54EA\u79CD\u5F00\u53D1\u548C\u90E8\u7F72\u65B9\u5F0F\uFF0C\u6211\u4EEC\u53EF\u4EE5\u53C2\u8003\u516C\u53F8\u5F53\u524D\u7684\u6280\u672F\u67B6\u6784\u6765\u51B3\u5B9A\u3002</p><p>\u5B9E\u9645\u4E0A\uFF0C\u79EF\u5206\u7CFB\u7EDF\u4E1A\u52A1\u6BD4\u8F83\u7B80\u5355\uFF0C\u4EE3\u7801\u91CF\u4E5F\u4E0D\u591A\uFF0C\u6211\u66F4\u503E\u5411\u4E8E\u5C06\u5B83\u8DDF\u8425\u9500\u7CFB\u7EDF\u653E\u5230\u4E00\u4E2A\u9879\u76EE\u4E2D\u5F00\u53D1\u90E8\u7F72\u3002\u53EA\u8981\u6211\u4EEC\u505A\u597D\u4EE3\u7801\u7684\u6A21\u5757\u5316\u548C\u89E3\u8026\uFF0C\u8BA9\u79EF\u5206\u76F8\u5173\u7684\u4E1A\u52A1\u4EE3\u7801\u8DDF\u5176\u4ED6\u4E1A\u52A1\u4EE3\u7801\u4E4B\u95F4\u8FB9\u754C\u6E05\u6670\uFF0C\u6CA1\u6709\u592A\u591A\u8026\u5408\uFF0C\u540E\u671F\u5982\u679C\u9700\u8981\u5C06\u5B83\u62C6\u5206\u6210\u72EC\u7ACB\u7684\u9879\u76EE\u6765\u5F00\u53D1\u90E8\u7F72\uFF0C\u90A3\u4E5F\u5E76\u4E0D\u56F0\u96BE\u3002</p><p>\u76F8\u4FE1\u8FD9\u6837\u4E00\u4E2A\u7B80\u5355\u7684\u4E1A\u52A1\u529F\u80FD\u7684\u5F00\u53D1\uFF0C\u5BF9\u4F60\u6765\u8BF4\u5E76\u6CA1\u6709\u592A\u5927\u96BE\u5EA6\u3002\u6240\u4EE5\uFF0C\u5177\u4F53\u7684\u4EE3\u7801\u5B9E\u73B0\u6211\u5C31\u4E0D\u5728\u4E13\u680F\u4E2D\u7ED9\u51FA\u4E86\u3002\u611F\u5174\u8DA3\u7684\u8BDD\uFF0C\u4F60\u53EF\u4EE5\u81EA\u5DF1\u5B9E\u73B0\u4E00\u4E0B\u3002\u63A5\u4E0B\u6765\u7684\u5185\u5BB9\uFF0C\u624D\u662F\u6211\u4EEC\u8FD9\u4E00\u8282\u7684\u91CD\u70B9\u3002</p><h2 id="\u4E3A\u4EC0\u4E48\u8981\u5206-mvc-\u4E09\u5C42\u5F00\u53D1" tabindex="-1"><a class="header-anchor" href="#\u4E3A\u4EC0\u4E48\u8981\u5206-mvc-\u4E09\u5C42\u5F00\u53D1" aria-hidden="true">#</a> \u4E3A\u4EC0\u4E48\u8981\u5206 MVC \u4E09\u5C42\u5F00\u53D1\uFF1F</h2><p>\u6211\u4EEC\u521A\u521A\u63D0\u5230\uFF0C\u5927\u90E8\u5206\u4E1A\u52A1\u7CFB\u7EDF\u7684\u5F00\u53D1\u90FD\u53EF\u4EE5\u5206\u4E3A\u4E09\u5C42\uFF1AContoller \u5C42\u3001Service \u5C42\u3001Repository \u5C42\u3002\u5BF9\u4E8E\u8FD9\u79CD\u5206\u5C42\u65B9\u5F0F\uFF0C\u6211\u76F8\u4FE1\u5927\u90E8\u5206\u4EBA\u90FD\u5F88\u8BA4\u540C\uFF0C\u751A\u81F3\u6210\u4E3A\u4E86\u4E00\u79CD\u5F00\u53D1\u4E60\u60EF\uFF0C\u4F46\u4F60\u6709\u6CA1\u6709\u60F3\u8FC7\uFF0C\u4E3A\u4EC0\u4E48\u6211\u4EEC\u8981\u5206\u5C42\u5F00\u53D1\uFF1F\u5F88\u591A\u4E1A\u52A1\u90FD\u6BD4\u8F83\u7B80\u5355\uFF0C\u4E00\u5C42\u4EE3\u7801\u641E\u5B9A\u6240\u6709\u7684\u6570\u636E\u8BFB\u53D6\u3001\u4E1A\u52A1\u903B\u8F91\u3001\u63A5\u53E3\u66B4\u9732\u4E0D\u597D\u5417\uFF1F\u4F60\u53EF\u4EE5\u628A\u5B83\u4F5C\u4E3A\u4E00\u9053\u9762\u8BD5\u9898\uFF0C\u8BD5\u7740\u81EA\u5DF1\u601D\u8003\u4E0B\uFF0C\u7136\u540E\u518D\u770B\u6211\u4E0B\u9762\u7684\u8BB2\u89E3\u3002</p><p>\u5BF9\u4E8E\u8FD9\u4E2A\u95EE\u9898\uFF0C\u6211\u603B\u7ED3\u4E86\u4EE5\u4E0B\u51E0\u70B9\u539F\u56E0\u3002</p><h3 id="_1-\u5206\u5C42\u80FD\u8D77\u5230\u4EE3\u7801\u590D\u7528\u7684\u4F5C\u7528" tabindex="-1"><a class="header-anchor" href="#_1-\u5206\u5C42\u80FD\u8D77\u5230\u4EE3\u7801\u590D\u7528\u7684\u4F5C\u7528" aria-hidden="true">#</a> 1. \u5206\u5C42\u80FD\u8D77\u5230\u4EE3\u7801\u590D\u7528\u7684\u4F5C\u7528</h3><p>\u540C\u4E00\u4E2A Repository \u53EF\u80FD\u4F1A\u88AB\u591A\u4E2A Service \u6765\u8C03\u7528\uFF0C\u540C\u4E00\u4E2A Service \u53EF\u80FD\u4F1A\u88AB\u591A\u4E2A Controller \u8C03\u7528\u3002\u6BD4\u5982\uFF0CUserService \u4E2D\u7684 getUserById() \u63A5\u53E3\u5C01\u88C5\u4E86\u901A\u8FC7 ID \u83B7\u53D6\u7528\u6237\u4FE1\u606F\u7684\u903B\u8F91\uFF0C\u8FD9\u90E8\u5206\u903B\u8F91\u53EF\u80FD\u4F1A\u88AB UserController \u548C AdminController \u7B49\u591A\u4E2A Controller \u4F7F\u7528\u3002\u5982\u679C\u6CA1\u6709 Service \u5C42\uFF0C\u6BCF\u4E2A Controller \u90FD\u8981\u91CD\u590D\u5B9E\u73B0\u8FD9\u90E8\u5206\u903B\u8F91\uFF0C\u663E\u7136\u4F1A\u8FDD\u53CD DRY \u539F\u5219\u3002</p><h3 id="_2-\u5206\u5C42\u80FD\u8D77\u5230\u9694\u79BB\u53D8\u5316\u7684\u4F5C\u7528" tabindex="-1"><a class="header-anchor" href="#_2-\u5206\u5C42\u80FD\u8D77\u5230\u9694\u79BB\u53D8\u5316\u7684\u4F5C\u7528" aria-hidden="true">#</a> 2. \u5206\u5C42\u80FD\u8D77\u5230\u9694\u79BB\u53D8\u5316\u7684\u4F5C\u7528</h3><p>\u5206\u5C42\u4F53\u73B0\u4E86\u4E00\u79CD\u62BD\u8C61\u548C\u5C01\u88C5\u7684\u8BBE\u8BA1\u601D\u60F3\u3002\u6BD4\u5982\uFF0CRepository \u5C42\u5C01\u88C5\u4E86\u5BF9\u6570\u636E\u5E93\u8BBF\u95EE\u7684\u64CD\u4F5C\uFF0C\u63D0\u4F9B\u4E86\u62BD\u8C61\u7684\u6570\u636E\u8BBF\u95EE\u63A5\u53E3\u3002\u57FA\u4E8E\u63A5\u53E3\u800C\u975E\u5B9E\u73B0\u7F16\u7A0B\u7684\u8BBE\u8BA1\u601D\u60F3\uFF0CService \u5C42\u4F7F\u7528 Repository \u5C42\u63D0\u4F9B\u7684\u63A5\u53E3\uFF0C\u5E76\u4E0D\u5173\u5FC3\u5176\u5E95\u5C42\u4F9D\u8D56\u7684\u662F\u54EA\u79CD\u5177\u4F53\u7684\u6570\u636E\u5E93\u3002\u5F53\u6211\u4EEC\u9700\u8981\u66FF\u6362\u6570\u636E\u5E93\u7684\u65F6\u5019\uFF0C\u6BD4\u5982\u4ECE MySQL \u5230 Oracle\uFF0C\u4ECE Oracle \u5230 Redis\uFF0C\u53EA\u9700\u8981\u6539\u52A8 Repository \u5C42\u7684\u4EE3\u7801\uFF0CService \u5C42\u7684\u4EE3\u7801\u5B8C\u5168\u4E0D\u9700\u8981\u4FEE\u6539\u3002</p><p>\u9664\u6B64\u4E4B\u5916\uFF0CController\u3001Service\u3001Repository \u4E09\u5C42\u4EE3\u7801\u7684\u7A33\u5B9A\u7A0B\u5EA6\u4E0D\u540C\u3001\u5F15\u8D77\u53D8\u5316\u7684\u539F\u56E0\u4E0D\u540C\uFF0C\u6240\u4EE5\u5206\u6210\u4E09\u5C42\u6765\u7EC4\u7EC7\u4EE3\u7801\uFF0C\u80FD\u6709\u6548\u5730\u9694\u79BB\u53D8\u5316\u3002\u6BD4\u5982\uFF0CRepository \u5C42\u57FA\u4E8E\u6570\u636E\u5E93\u8868\uFF0C\u800C\u6570\u636E\u5E93\u8868\u6539\u52A8\u7684\u53EF\u80FD\u6027\u5F88\u5C0F\uFF0C\u6240\u4EE5 Repository \u5C42\u7684\u4EE3\u7801\u6700\u7A33\u5B9A\uFF0C\u800C Controller \u5C42\u63D0\u4F9B\u9002\u914D\u7ED9\u5916\u90E8\u4F7F\u7528\u7684\u63A5\u53E3\uFF0C\u4EE3\u7801\u7ECF\u5E38\u4F1A\u53D8\u52A8\u3002\u5206\u5C42\u4E4B\u540E\uFF0CController \u5C42\u4E2D\u4EE3\u7801\u7684\u9891\u7E41\u6539\u52A8\u5E76\u4E0D\u4F1A\u5F71\u54CD\u5230\u7A33\u5B9A\u7684 Repository \u5C42\u3002</p><h3 id="_3-\u5206\u5C42\u80FD\u8D77\u5230\u9694\u79BB\u5173\u6CE8\u70B9\u7684\u4F5C\u7528" tabindex="-1"><a class="header-anchor" href="#_3-\u5206\u5C42\u80FD\u8D77\u5230\u9694\u79BB\u5173\u6CE8\u70B9\u7684\u4F5C\u7528" aria-hidden="true">#</a> 3. \u5206\u5C42\u80FD\u8D77\u5230\u9694\u79BB\u5173\u6CE8\u70B9\u7684\u4F5C\u7528</h3><p>Repository \u5C42\u53EA\u5173\u6CE8\u6570\u636E\u7684\u8BFB\u5199\u3002Service \u5C42\u53EA\u5173\u6CE8\u4E1A\u52A1\u903B\u8F91\uFF0C\u4E0D\u5173\u6CE8\u6570\u636E\u7684\u6765\u6E90\u3002Controller \u5C42\u53EA\u5173\u6CE8\u4E0E\u5916\u754C\u6253\u4EA4\u9053\uFF0C\u6570\u636E\u6821\u9A8C\u3001\u5C01\u88C5\u3001\u683C\u5F0F\u8F6C\u6362\uFF0C\u5E76\u4E0D\u5173\u5FC3\u4E1A\u52A1\u903B\u8F91\u3002\u4E09\u5C42\u4E4B\u95F4\u7684\u5173\u6CE8\u70B9\u4E0D\u540C\uFF0C\u5206\u5C42\u4E4B\u540E\uFF0C\u804C\u8D23\u5206\u660E\uFF0C\u66F4\u52A0\u7B26\u5408\u5355\u4E00\u804C\u8D23\u539F\u5219\uFF0C\u4EE3\u7801\u7684\u5185\u805A\u6027\u66F4\u597D\u3002</p><h3 id="_4-\u5206\u5C42\u80FD\u63D0\u9AD8\u4EE3\u7801\u7684\u53EF\u6D4B\u8BD5\u6027" tabindex="-1"><a class="header-anchor" href="#_4-\u5206\u5C42\u80FD\u63D0\u9AD8\u4EE3\u7801\u7684\u53EF\u6D4B\u8BD5\u6027" aria-hidden="true">#</a> 4. \u5206\u5C42\u80FD\u63D0\u9AD8\u4EE3\u7801\u7684\u53EF\u6D4B\u8BD5\u6027</h3><p>\u540E\u9762\u8BB2\u5355\u5143\u6D4B\u8BD5\u7684\u65F6\u5019\uFF0C\u6211\u4EEC\u4F1A\u8BB2\u5230\uFF0C\u5355\u5143\u6D4B\u8BD5\u4E0D\u4F9D\u8D56\u4E0D\u53EF\u63A7\u7684\u5916\u90E8\u7EC4\u4EF6\uFF0C\u6BD4\u5982\u6570\u636E\u5E93\u3002\u5206\u5C42\u4E4B\u540E\uFF0CRepsitory \u5C42\u7684\u4EE3\u7801\u901A\u8FC7\u4F9D\u8D56\u6CE8\u5165\u7684\u65B9\u5F0F\u4F9B Service \u5C42\u4F7F\u7528\uFF0C\u5F53\u8981\u6D4B\u8BD5\u5305\u542B\u6838\u5FC3\u4E1A\u52A1\u903B\u8F91\u7684 Service \u5C42\u4EE3\u7801\u7684\u65F6\u5019\uFF0C\u6211\u4EEC\u53EF\u4EE5\u7528 mock \u7684\u6570\u636E\u6E90\u66FF\u4EE3\u771F\u5B9E\u7684\u6570\u636E\u5E93\uFF0C\u6CE8\u5165\u5230 Service \u5C42\u4EE3\u7801\u4E2D\u3002\u4EE3\u7801\u7684\u53EF\u6D4B\u8BD5\u6027\u548C\u5355\u5143\u6D4B\u8BD5\u6211\u4EEC\u540E\u9762\u4F1A\u8BB2\u5230\uFF0C\u8FD9\u91CC\u4F60\u7A0D\u5FAE\u4E86\u89E3\u5373\u53EF\u3002</p><h3 id="_5-\u5206\u5C42\u80FD\u5E94\u5BF9\u7CFB\u7EDF\u7684\u590D\u6742\u6027" tabindex="-1"><a class="header-anchor" href="#_5-\u5206\u5C42\u80FD\u5E94\u5BF9\u7CFB\u7EDF\u7684\u590D\u6742\u6027" aria-hidden="true">#</a> 5. \u5206\u5C42\u80FD\u5E94\u5BF9\u7CFB\u7EDF\u7684\u590D\u6742\u6027</h3><p>\u6240\u6709\u7684\u4EE3\u7801\u90FD\u653E\u5230\u4E00\u4E2A\u7C7B\u4E2D\uFF0C\u90A3\u8FD9\u4E2A\u7C7B\u7684\u4EE3\u7801\u5C31\u4F1A\u56E0\u4E3A\u9700\u6C42\u7684\u8FED\u4EE3\u800C\u65E0\u9650\u81A8\u80C0\u3002\u6211\u4EEC\u77E5\u9053\uFF0C\u5F53\u4E00\u4E2A\u7C7B\u6216\u4E00\u4E2A\u51FD\u6570\u7684\u4EE3\u7801\u8FC7\u591A\u4E4B\u540E\uFF0C\u53EF\u8BFB\u6027\u3001\u53EF\u7EF4\u62A4\u6027\u5C31\u4F1A\u53D8\u5DEE\u3002\u90A3\u6211\u4EEC\u5C31\u8981\u60F3\u529E\u6CD5\u62C6\u5206\u3002\u62C6\u5206\u6709\u5782\u76F4\u548C\u6C34\u5E73\u4E24\u4E2A\u65B9\u5411\u3002\u6C34\u5E73\u65B9\u5411\u57FA\u4E8E\u4E1A\u52A1\u6765\u505A\u62C6\u5206\uFF0C\u5C31\u662F\u6A21\u5757\u5316\uFF1B\u5782\u76F4\u65B9\u5411\u57FA\u4E8E\u6D41\u7A0B\u6765\u505A\u62C6\u5206\uFF0C\u5C31\u662F\u8FD9\u91CC\u8BF4\u7684\u5206\u5C42\u3002</p><p>\u8FD8\u662F\u90A3\u53E5\u8BDD\uFF0C\u4E0D\u7BA1\u662F\u5206\u5C42\u3001\u6A21\u5757\u5316\uFF0C\u8FD8\u662F OOP\u3001DDD\uFF0C\u4EE5\u53CA\u5404\u79CD\u8BBE\u8BA1\u6A21\u5F0F\u3001\u539F\u5219\u548C\u601D\u60F3\uFF0C\u90FD\u662F\u4E3A\u4E86\u5E94\u5BF9\u590D\u6742\u7CFB\u7EDF\uFF0C\u5E94\u5BF9\u7CFB\u7EDF\u7684\u590D\u6742\u6027\u3002\u5BF9\u4E8E\u7B80\u5355\u7CFB\u7EDF\u6765\u8BF4\uFF0C\u5176\u5B9E\u662F\u53D1\u6325\u4E0D\u4E86\u4F5C\u7528\u7684\uFF0C\u5C31\u662F\u4FD7\u8BDD\u8BF4\u7684\u201C\u6740\u9E21\u7109\u7528\u725B\u5200\u201D\u3002</p><h2 id="bo\u3001vo\u3001entity-\u5B58\u5728\u7684\u610F\u4E49\u662F\u4EC0\u4E48" tabindex="-1"><a class="header-anchor" href="#bo\u3001vo\u3001entity-\u5B58\u5728\u7684\u610F\u4E49\u662F\u4EC0\u4E48" aria-hidden="true">#</a> BO\u3001VO\u3001Entity \u5B58\u5728\u7684\u610F\u4E49\u662F\u4EC0\u4E48\uFF1F</h2><p>\u5728\u524D\u9762\u7684\u7AE0\u8282\u4E2D\uFF0C\u6211\u4EEC\u63D0\u5230\uFF0C\u9488\u5BF9 Controller\u3001Service\u3001Repository \u4E09\u5C42\uFF0C\u6BCF\u5C42\u90FD\u4F1A\u5B9A\u4E49\u76F8\u5E94\u7684\u6570\u636E\u5BF9\u8C61\uFF0C\u5B83\u4EEC\u5206\u522B\u662F VO\uFF08View Object\uFF09\u3001BO\uFF08Business Object\uFF09\u3001Entity\uFF0C\u4F8B\u5982 UserVo\u3001UserBo\u3001UserEntity\u3002\u5728\u5B9E\u9645\u7684\u5F00\u53D1\u4E2D\uFF0CVO\u3001BO\u3001Entity \u53EF\u80FD\u5B58\u5728\u5927\u91CF\u7684\u91CD\u590D\u5B57\u6BB5\uFF0C\u751A\u81F3\u4E09\u8005\u5305\u542B\u7684\u5B57\u6BB5\u5B8C\u5168\u4E00\u6837\u3002\u5728\u5F00\u53D1\u7684\u8FC7\u7A0B\u4E2D\uFF0C\u6211\u4EEC\u7ECF\u5E38\u9700\u8981\u91CD\u590D\u5B9A\u4E49\u4E09\u4E2A\u51E0\u4E4E\u4E00\u6837\u7684\u7C7B\uFF0C\u663E\u7136\u662F\u4E00\u79CD\u91CD\u590D\u52B3\u52A8\u3002</p><p><strong>\u76F8\u5BF9\u4E8E\u6BCF\u5C42\u5B9A\u4E49\u5404\u81EA\u7684\u6570\u636E\u5BF9\u8C61\u6765\u8BF4\uFF0C\u662F\u4E0D\u662F\u5B9A\u4E49\u4E00\u4E2A\u516C\u5171\u7684\u6570\u636E\u5BF9\u8C61\u66F4\u597D\u4E9B\u5462\uFF1F</strong></p><p>\u5B9E\u9645\u4E0A\uFF0C\u6211\u66F4\u52A0\u63A8\u8350\u6BCF\u5C42\u90FD\u5B9A\u4E49\u5404\u81EA\u7684\u6570\u636E\u5BF9\u8C61\u8FD9\u79CD\u8BBE\u8BA1\u601D\u8DEF\uFF0C\u4E3B\u8981\u6709\u4EE5\u4E0B 3 \u4E2A\u65B9\u9762\u7684\u539F\u56E0\u3002</p><p>VO\u3001BO\u3001Entity \u5E76\u975E\u5B8C\u5168\u4E00\u6837\u3002\u6BD4\u5982\uFF0C\u6211\u4EEC\u53EF\u4EE5\u5728 UserEntity\u3001UserBo \u4E2D\u5B9A\u4E49 Password \u5B57\u6BB5\uFF0C\u4F46\u663E\u7136\u4E0D\u80FD\u5728 UserVo \u4E2D\u5B9A\u4E49 Password \u5B57\u6BB5\uFF0C\u5426\u5219\u5C31\u4F1A\u5C06\u7528\u6237\u7684\u5BC6\u7801\u66B4\u9732\u51FA\u53BB\u3002</p><p>VO\u3001BO\u3001Entity \u4E09\u4E2A\u7C7B\u867D\u7136\u4EE3\u7801\u91CD\u590D\uFF0C\u4F46\u529F\u80FD\u8BED\u4E49\u4E0D\u91CD\u590D\uFF0C\u4ECE\u804C\u8D23\u4E0A\u8BB2\u662F\u4E0D\u4E00\u6837\u7684\u3002\u6240\u4EE5\uFF0C\u4E5F\u5E76\u4E0D\u80FD\u7B97\u8FDD\u80CC DRY \u539F\u5219\u3002\u5728\u524D\u9762\u8BB2\u5230 DRY \u539F\u5219\u7684\u65F6\u5019\uFF0C\u9488\u5BF9\u8FD9\u79CD\u60C5\u51B5\uFF0C\u5982\u679C\u5408\u5E76\u4E3A\u540C\u4E00\u4E2A\u7C7B\uFF0C\u90A3\u4E5F\u4F1A\u5B58\u5728\u540E\u671F\u56E0\u4E3A\u9700\u6C42\u7684\u53D8\u5316\u800C\u9700\u8981\u518D\u62C6\u5206\u7684\u95EE\u9898\u3002</p><p>\u4E3A\u4E86\u5C3D\u91CF\u51CF\u5C11\u6BCF\u5C42\u4E4B\u95F4\u7684\u8026\u5408\uFF0C\u628A\u804C\u8D23\u8FB9\u754C\u5212\u5206\u660E\u786E\uFF0C\u6BCF\u5C42\u90FD\u4F1A\u7EF4\u62A4\u81EA\u5DF1\u7684\u6570\u636E\u5BF9\u8C61\uFF0C\u5C42\u4E0E\u5C42\u4E4B\u95F4\u901A\u8FC7\u63A5\u53E3\u4EA4\u4E92\u3002\u6570\u636E\u4ECE\u4E0B\u4E00\u5C42\u4F20\u9012\u5230\u4E0A\u4E00\u5C42\u7684\u65F6\u5019\uFF0C\u5C06\u4E0B\u4E00\u5C42\u7684\u6570\u636E\u5BF9\u8C61\u8F6C\u5316\u6210\u4E0A\u4E00\u5C42\u7684\u6570\u636E\u5BF9\u8C61\uFF0C\u518D\u7EE7\u7EED\u5904\u7406\u3002\u867D\u7136\u8FD9\u6837\u7684\u8BBE\u8BA1\u7A0D\u5FAE\u6709\u4E9B\u7E41\u7410\uFF0C\u6BCF\u5C42\u90FD\u9700\u8981\u5B9A\u4E49\u5404\u81EA\u7684\u6570\u636E\u5BF9\u8C61\uFF0C\u9700\u8981\u505A\u6570\u636E\u5BF9\u8C61\u4E4B\u95F4\u7684\u8F6C\u5316\uFF0C\u4F46\u662F\u5206\u5C42\u6E05\u6670\u3002\u5BF9\u4E8E\u975E\u5E38\u5927\u7684\u9879\u76EE\u6765\u8BF4\uFF0C\u7ED3\u6784\u6E05\u6670\u662F\u7B2C\u4E00\u4F4D\u7684\uFF01</p><p><strong>\u65E2\u7136 VO\u3001BO\u3001Entity \u4E0D\u80FD\u5408\u5E76\uFF0C\u90A3\u5982\u4F55\u89E3\u51B3\u4EE3\u7801\u91CD\u590D\u7684\u95EE\u9898\u5462\uFF1F</strong></p><p>\u4ECE\u8BBE\u8BA1\u7684\u89D2\u5EA6\u6765\u8BF4\uFF0CVO\u3001BO\u3001Entity \u7684\u8BBE\u8BA1\u601D\u8DEF\u5E76\u4E0D\u8FDD\u53CD DRY \u539F\u5219\uFF0C\u4E3A\u4E86\u5206\u5C42\u6E05\u6670\u3001\u51CF\u5C11\u8026\u5408\uFF0C\u591A\u7EF4\u62A4\u51E0\u4E2A\u7C7B\u7684\u6210\u672C\u4E5F\u5E76\u4E0D\u662F\u4E0D\u80FD\u63A5\u53D7\u7684\u3002\u4F46\u662F\uFF0C\u5982\u679C\u4F60\u771F\u7684\u6709\u4EE3\u7801\u6D01\u7656\uFF0C\u5BF9\u4E8E\u4EE3\u7801\u91CD\u590D\u7684\u95EE\u9898\uFF0C\u6211\u4EEC\u4E5F\u6709\u4E00\u4E9B\u529E\u6CD5\u6765\u89E3\u51B3\u3002</p><p>\u6211\u4EEC\u524D\u9762\u8BB2\u5230\uFF0C\u7EE7\u627F\u53EF\u4EE5\u89E3\u51B3\u4EE3\u7801\u91CD\u590D\u95EE\u9898\u3002\u6211\u4EEC\u53EF\u4EE5\u5C06\u516C\u5171\u7684\u5B57\u6BB5\u5B9A\u4E49\u5728\u7236\u7C7B\u4E2D\uFF0C\u8BA9 VO\u3001BO\u3001Entity \u90FD\u7EE7\u627F\u8FD9\u4E2A\u7236\u7C7B\uFF0C\u5404\u81EA\u53EA\u5B9A\u4E49\u7279\u6709\u7684\u5B57\u6BB5\u3002\u56E0\u4E3A\u8FD9\u91CC\u7684\u7EE7\u627F\u5C42\u6B21\u5F88\u6D45\uFF0C\u4E5F\u4E0D\u590D\u6742\uFF0C\u6240\u4EE5\u4F7F\u7528\u7EE7\u627F\u5E76\u4E0D\u4F1A\u5F71\u54CD\u4EE3\u7801\u7684\u53EF\u8BFB\u6027\u548C\u53EF\u7EF4\u62A4\u6027\u3002\u540E\u671F\u5982\u679C\u56E0\u4E3A\u4E1A\u52A1\u7684\u9700\u8981\uFF0C\u6709\u4E9B\u5B57\u6BB5\u9700\u8981\u4ECE\u7236\u7C7B\u79FB\u52A8\u5230\u5B50\u7C7B\uFF0C\u6216\u8005\u4ECE\u5B50\u7C7B\u63D0\u53D6\u5230\u7236\u7C7B\uFF0C\u4EE3\u7801\u6539\u8D77\u6765\u4E5F\u5E76\u4E0D\u590D\u6742\u3002</p><p>\u524D\u9762\u5728\u8BB2\u201C\u591A\u7528\u7EC4\u5408\uFF0C\u5C11\u7528\u7EE7\u627F\u201D\u8BBE\u8BA1\u601D\u60F3\u7684\u65F6\u5019\uFF0C\u6211\u4EEC\u63D0\u5230\uFF0C\u7EC4\u5408\u4E5F\u53EF\u4EE5\u89E3\u51B3\u4EE3\u7801\u91CD\u590D\u7684\u95EE\u9898\uFF0C\u6240\u4EE5\uFF0C\u8FD9\u91CC\u6211\u4EEC\u8FD8\u53EF\u4EE5\u5C06\u516C\u5171\u7684\u5B57\u6BB5\u62BD\u53D6\u5230\u516C\u5171\u7684\u7C7B\u4E2D\uFF0CVO\u3001BO\u3001Entity \u901A\u8FC7\u7EC4\u5408\u5173\u7CFB\u6765\u590D\u7528\u8FD9\u4E2A\u7C7B\u7684\u4EE3\u7801\u3002</p><p><strong>\u4EE3\u7801\u91CD\u590D\u95EE\u9898\u89E3\u51B3\u4E86\uFF0C\u90A3\u4E0D\u540C\u5206\u5C42\u4E4B\u95F4\u7684\u6570\u636E\u5BF9\u8C61\u8BE5\u5982\u4F55\u4E92\u76F8\u8F6C\u5316\u5462\uFF1F</strong></p><p>\u5F53\u4E0B\u4E00\u5C42\u7684\u6570\u636E\u901A\u8FC7\u63A5\u53E3\u8C03\u7528\u4F20\u9012\u5230\u4E0A\u4E00\u5C42\u4E4B\u540E\uFF0C\u6211\u4EEC\u9700\u8981\u5C06\u5B83\u8F6C\u5316\u6210\u4E0A\u4E00\u5C42\u5BF9\u5E94\u7684\u6570\u636E\u5BF9\u8C61\u7C7B\u578B\u3002\u6BD4\u5982\uFF0CService \u5C42\u4ECE Repository \u5C42\u83B7\u53D6\u7684 Entity \u4E4B\u540E\uFF0C\u5C06\u5176\u8F6C\u5316\u6210 BO\uFF0C\u518D\u7EE7\u7EED\u4E1A\u52A1\u903B\u8F91\u7684\u5904\u7406\u3002\u6240\u4EE5\uFF0C\u6574\u4E2A\u5F00\u53D1\u7684\u8FC7\u7A0B\u4F1A\u6D89\u53CA\u201CEntity \u5230 BO\u201D\u548C\u201CBO \u5230 VO\u201D\u8FD9\u4E24\u79CD\u8F6C\u5316\u3002</p><p>\u6700\u7B80\u5355\u7684\u8F6C\u5316\u65B9\u5F0F\u662F\u624B\u52A8\u590D\u5236\u3002\u81EA\u5DF1\u5199\u4EE3\u7801\u5728\u4E24\u4E2A\u5BF9\u8C61\u4E4B\u95F4\uFF0C\u4E00\u4E2A\u5B57\u6BB5\u4E00\u4E2A\u5B57\u6BB5\u7684\u8D4B\u503C\u3002\u4F46\u8FD9\u6837\u7684\u505A\u6CD5\u663E\u7136\u662F\u6CA1\u6709\u6280\u672F\u542B\u91CF\u7684\u4F4E\u7EA7\u52B3\u52A8\u3002Java \u4E2D\u63D0\u4F9B\u4E86\u591A\u79CD\u6570\u636E\u5BF9\u8C61\u8F6C\u5316\u5DE5\u5177\uFF0C\u6BD4\u5982 BeanUtils\u3001Dozer \u7B49\uFF0C\u53EF\u4EE5\u5927\u5927\u7B80\u5316\u7E41\u7410\u7684\u5BF9\u8C61\u8F6C\u5316\u5DE5\u4F5C\u3002\u5982\u679C\u4F60\u662F\u7528\u5176\u4ED6\u7F16\u7A0B\u8BED\u8A00\u6765\u505A\u5F00\u53D1\uFF0C\u4E5F\u53EF\u4EE5\u501F\u9274 Java \u8FD9\u4E9B\u5DE5\u5177\u7C7B\u7684\u8BBE\u8BA1\u601D\u8DEF\uFF0C\u81EA\u5DF1\u5728\u9879\u76EE\u4E2D\u5B9E\u73B0\u5BF9\u8C61\u8F6C\u5316\u5DE5\u5177\u7C7B\u3002</p><p><strong>VO\u3001BO\u3001Entity \u90FD\u662F\u57FA\u4E8E\u8D2B\u8840\u6A21\u578B\u7684\uFF0C\u800C\u4E14\u4E3A\u4E86\u517C\u5BB9\u6846\u67B6\u6216\u5F00\u53D1\u5E93\uFF08\u6BD4\u5982 MyBatis\u3001Dozer\u3001BeanUtils\uFF09\uFF0C\u6211\u4EEC\u8FD8\u9700\u8981\u5B9A\u4E49\u6BCF\u4E2A\u5B57\u6BB5\u7684 set \u65B9\u6CD5\u3002\u8FD9\u4E9B\u90FD\u8FDD\u80CC OOP \u7684\u5C01\u88C5\u7279\u6027\uFF0C\u4F1A\u5BFC\u81F4\u6570\u636E\u88AB\u968F\u610F\u4FEE\u6539\u3002\u90A3\u5230\u5E95\u8BE5\u600E\u4E48\u529E\u597D\u5462\uFF1F</strong></p><p>\u524D\u9762\u6211\u4EEC\u4E5F\u63D0\u5230\u8FC7\uFF0CEntity \u548C VO \u7684\u751F\u547D\u5468\u671F\u662F\u6709\u9650\u7684\uFF0C\u90FD\u4EC5\u9650\u5728\u672C\u5C42\u8303\u56F4\u5185\u3002\u800C\u5BF9\u5E94\u7684 Repository \u5C42\u548C Controller \u5C42\u4E5F\u90FD\u4E0D\u5305\u542B\u592A\u591A\u4E1A\u52A1\u903B\u8F91\uFF0C\u6240\u4EE5\u4E5F\u4E0D\u4F1A\u6709\u592A\u591A\u4EE3\u7801\u968F\u610F\u4FEE\u6539\u6570\u636E\uFF0C\u5373\u4FBF\u8BBE\u8BA1\u6210\u8D2B\u8840\u3001\u5B9A\u4E49\u6BCF\u4E2A\u5B57\u6BB5\u7684 set \u65B9\u6CD5\uFF0C\u76F8\u5BF9\u6765\u8BF4\u4E5F\u662F\u5B89\u5168\u7684\u3002</p><p>\u4E0D\u8FC7\uFF0CService \u5C42\u5305\u542B\u6BD4\u8F83\u591A\u7684\u4E1A\u52A1\u903B\u8F91\u4EE3\u7801\uFF0C\u6240\u4EE5 BO \u5C31\u5B58\u5728\u88AB\u4EFB\u610F\u4FEE\u6539\u7684\u98CE\u9669\u4E86\u3002\u4F46\u662F\uFF0C\u8BBE\u8BA1\u7684\u95EE\u9898\u672C\u8EAB\u5C31\u6CA1\u6709\u6700\u4F18\u89E3\uFF0C\u53EA\u6709\u6743\u8861\u3002\u4E3A\u4E86\u4F7F\u7528\u65B9\u4FBF\uFF0C\u6211\u4EEC\u53EA\u80FD\u505A\u4E00\u4E9B\u59A5\u534F\uFF0C\u653E\u5F03 BO \u7684\u5C01\u88C5\u7279\u6027\uFF0C\u7531\u7A0B\u5E8F\u5458\u81EA\u5DF1\u6765\u8D1F\u8D23\u8FD9\u4E9B\u6570\u636E\u5BF9\u8C61\u7684\u4E0D\u88AB\u9519\u8BEF\u4F7F\u7528\u3002</p><h2 id="\u603B\u7ED3\u7528\u5230\u7684\u8BBE\u8BA1\u539F\u5219\u548C\u601D\u60F3" tabindex="-1"><a class="header-anchor" href="#\u603B\u7ED3\u7528\u5230\u7684\u8BBE\u8BA1\u539F\u5219\u548C\u601D\u60F3" aria-hidden="true">#</a> \u603B\u7ED3\u7528\u5230\u7684\u8BBE\u8BA1\u539F\u5219\u548C\u601D\u60F3</h2><p>\u524D\u9762\u6211\u4EEC\u63D0\u5230\uFF0C\u5F88\u591A\u4EBA\u505A\u4E1A\u52A1\u5F00\u53D1\uFF0C\u603B\u611F\u89C9\u5C31\u662F CRUD\uFF0C\u7FFB\u8BD1\u4EE3\u7801\uFF0C\u6839\u672C\u7528\u4E0D\u5230\u8BBE\u8BA1\u539F\u5219\u3001\u601D\u60F3\u548C\u6A21\u5F0F\u3002\u5B9E\u9645\u4E0A\uFF0C\u53EA\u662F\u4F60\u6CA1\u6709\u53D1\u73B0\u800C\u5DF2\u3002\u73B0\u5728\uFF0C\u6211\u5C31\u7ED9\u4F60\u7F57\u5217\u4E00\u4E0B\uFF0C\u4ECA\u5929\u8BB2\u89E3\u7684\u5185\u5BB9\u4E2D\uFF0C\u90FD\u7528\u5230\u4E86\u54EA\u4E9B\u8BBE\u8BA1\u539F\u5219\u3001\u601D\u60F3\u548C\u6A21\u5F0F\u3002</p><p><img src="https://personal-site-pictures.oss-cn-beijing.aliyuncs.com/img/image-20220612120344054.png" alt="image-20220612120344054" loading="lazy"></p><h2 id="\u91CD\u70B9\u56DE\u987E" tabindex="-1"><a class="header-anchor" href="#\u91CD\u70B9\u56DE\u987E" aria-hidden="true">#</a> \u91CD\u70B9\u56DE\u987E</h2><p>\u6280\u672F\u4EBA\u4E5F\u8981\u6709\u4E00\u4E9B\u4EA7\u54C1\u601D\u7EF4\u3002\u5BF9\u4E8E\u4EA7\u54C1\u8BBE\u8BA1\u3001\u9700\u6C42\u5206\u6790\uFF0C\u6211\u4EEC\u8981\u5B66\u4F1A\u201C\u501F\u9274\u201D\uFF0C\u4E00\u5B9A\u4E0D\u8981\u81EA\u5DF1\u95F7\u5934\u60F3\u3002\u4E00\u65B9\u9762\u8FD9\u6837\u505A\u5F88\u96BE\u60F3\u5168\u9762\uFF0C\u53E6\u4E00\u65B9\u9762\u4ECE\u96F6\u5F00\u59CB\u8BBE\u8BA1\u4E5F\u6BD4\u8F83\u6D6A\u8D39\u65F6\u95F4\u3002\u9664\u6B64\u4E4B\u5916\uFF0C\u6211\u4EEC\u8FD8\u53EF\u4EE5\u901A\u8FC7\u7EBF\u6846\u56FE\u548C\u7528\u6237\u7528\u4F8B\u6765\u7EC6\u5316\u4E1A\u52A1\u6D41\u7A0B\uFF0C\u6316\u6398\u4E00\u4E9B\u6BD4\u8F83\u7EC6\u8282\u7684\u3001\u4E0D\u5BB9\u6613\u60F3\u5230\u7684\u529F\u80FD\u70B9\u3002</p><p>\u9762\u5411\u5BF9\u8C61\u8BBE\u8BA1\u805A\u7126\u5728\u4EE3\u7801\u5C42\u9762\uFF08\u4E3B\u8981\u662F\u9488\u5BF9\u7C7B\uFF09\uFF0C\u90A3\u7CFB\u7EDF\u8BBE\u8BA1\u5C31\u662F\u805A\u7126\u5728\u67B6\u6784\u5C42\u9762\uFF08\u4E3B\u8981\u662F\u9488\u5BF9\u6A21\u5757\uFF09\uFF0C\u4E24\u8005\u6709\u5F88\u591A\u76F8\u4F3C\u4E4B\u5904\u3002\u5F88\u591A\u8BBE\u8BA1\u539F\u5219\u548C\u601D\u60F3\u4E0D\u4EC5\u4EC5\u53EF\u4EE5\u5E94\u7528\u5230\u4EE3\u7801\u8BBE\u8BA1\u4E2D\uFF0C\u8FD8\u80FD\u7528\u5230\u67B6\u6784\u8BBE\u8BA1\u4E2D\u3002\u5B9E\u9645\u4E0A\uFF0C\u6211\u4EEC\u53EF\u4EE5\u501F\u9274\u9762\u5411\u5BF9\u8C61\u8BBE\u8BA1\u7684\u6B65\u9AA4\uFF0C\u6765\u505A\u7CFB\u7EDF\u8BBE\u8BA1\u3002</p><p>\u9762\u5411\u5BF9\u8C61\u8BBE\u8BA1\u7684\u672C\u8D28\u5C31\u662F\u628A\u5408\u9002\u7684\u4EE3\u7801\u653E\u5230\u5408\u9002\u7684\u7C7B\u4E2D\u3002\u5408\u7406\u5730\u5212\u5206\u4EE3\u7801\u53EF\u4EE5\u5B9E\u73B0\u4EE3\u7801\u7684\u9AD8\u5185\u805A\u3001\u4F4E\u8026\u5408\uFF0C\u7C7B\u4E0E\u7C7B\u4E4B\u95F4\u7684\u4EA4\u4E92\u7B80\u5355\u6E05\u6670\uFF0C\u4EE3\u7801\u6574\u4F53\u7ED3\u6784\u4E00\u76EE\u4E86\u7136\u3002\u7C7B\u6BD4\u9762\u5411\u5BF9\u8C61\u8BBE\u8BA1\uFF0C\u7CFB\u7EDF\u8BBE\u8BA1\u5B9E\u9645\u4E0A\u5C31\u662F\u5C06\u5408\u9002\u7684\u529F\u80FD\u653E\u5230\u5408\u9002\u7684\u6A21\u5757\u4E2D\u3002\u5408\u7406\u5730\u5212\u5206\u6A21\u5757\u4E5F\u53EF\u4EE5\u505A\u5230\u6A21\u5757\u5C42\u9762\u7684\u9AD8\u5185\u805A\u3001\u4F4E\u8026\u5408\uFF0C\u67B6\u6784\u6574\u6D01\u6E05\u6670\u3002\u5728\u9762\u5411\u5BF9\u8C61\u8BBE\u8BA1\u4E2D\uFF0C\u7C7B\u8BBE\u8BA1\u597D\u4E4B\u540E\uFF0C\u6211\u4EEC\u9700\u8981\u8BBE\u8BA1\u7C7B\u4E4B\u95F4\u7684\u4EA4\u4E92\u5173\u7CFB\u3002\u7C7B\u6BD4\u5230\u7CFB\u7EDF\u8BBE\u8BA1\uFF0C\u7CFB\u7EDF\u804C\u8D23\u5212\u5206\u597D\u4E4B\u540E\uFF0C\u63A5\u4E0B\u6765\u5C31\u662F\u8BBE\u8BA1\u7CFB\u7EDF\u4E4B\u95F4\u7684\u4EA4\u4E92\u4E86\u3002</p><hr><p><strong>1. \u4E3A\u4EC0\u4E48\u8981\u5206 MVC \u4E09\u5C42\u5F00\u53D1\uFF1F</strong></p><p>\u5BF9\u4E8E\u8FD9\u4E2A\u95EE\u9898\uFF0C\u6211\u603B\u7ED3\u4E86\u4EE5\u4E0B 5 \u70B9\u539F\u56E0\u3002</p><ul><li><p>\u5206\u5C42\u80FD\u8D77\u5230\u4EE3\u7801\u590D\u7528\u7684\u4F5C\u7528</p></li><li><p>\u5206\u5C42\u80FD\u8D77\u5230\u9694\u79BB\u53D8\u5316\u7684\u4F5C\u7528</p></li><li><p>\u5206\u5C42\u80FD\u8D77\u5230\u9694\u79BB\u5173\u6CE8\u70B9\u7684\u4F5C\u7528</p></li><li><p>\u5206\u5C42\u80FD\u63D0\u9AD8\u4EE3\u7801\u7684\u53EF\u6D4B\u8BD5\u6027</p></li><li><p>\u5206\u5C42\u80FD\u5E94\u5BF9\u7CFB\u7EDF\u7684\u590D\u6742\u6027</p></li></ul><p><strong>2.BO\u3001VO\u3001Entity \u5B58\u5728\u7684\u610F\u4E49\u662F\u4EC0\u4E48\uFF1F</strong></p><p>\u4ECE\u8BBE\u8BA1\u7684\u89D2\u5EA6\u6765\u8BF4\uFF0CVO\u3001BO\u3001Entity \u7684\u8BBE\u8BA1\u601D\u8DEF\u5E76\u4E0D\u8FDD\u53CD DRY \u539F\u5219\uFF0C\u4E3A\u4E86\u5206\u5C42\u6E05\u6670\u3001\u51CF\u5C11\u8026\u5408\uFF0C\u591A\u7EF4\u62A4\u51E0\u4E2A\u7C7B\u7684\u6210\u672C\u4E5F\u5E76\u4E0D\u662F\u4E0D\u80FD\u63A5\u53D7\u7684\u3002\u4F46\u662F\uFF0C\u5982\u679C\u4F60\u771F\u7684\u6709\u4EE3\u7801\u6D01\u7656\uFF0C\u5BF9\u4E8E\u4EE3\u7801\u91CD\u590D\u7684\u95EE\u9898\uFF0C\u6211\u4EEC\u53EF\u4EE5\u901A\u8FC7\u7EE7\u627F\u6216\u8005\u7EC4\u5408\u6765\u89E3\u51B3\u3002</p><p>\u5982\u4F55\u8FDB\u884C\u6570\u636E\u5BF9\u8C61\u4E4B\u95F4\u7684\u8F6C\u5316\uFF1F\u6700\u7B80\u5355\u7684\u65B9\u5F0F\u5C31\u662F\u624B\u52A8\u590D\u5236\u3002\u5F53\u7136\uFF0C\u4F60\u4E5F\u53EF\u4EE5\u4F7F\u7528 Java \u4E2D\u63D0\u4F9B\u4E86\u6570\u636E\u5BF9\u8C61\u8F6C\u5316\u5DE5\u5177\uFF0C\u6BD4\u5982 BeanUtils\u3001Dozer \u7B49\uFF0C\u53EF\u4EE5\u5927\u5927\u7B80\u5316\u7E41\u7410\u7684\u5BF9\u8C61\u8F6C\u5316\u5DE5\u4F5C\u3002</p><p>\u5C3D\u7BA1 VO\u3001BO\u3001Entity \u7684\u8BBE\u8BA1\u8FDD\u80CC OOP \u7684\u5C01\u88C5\u7279\u6027\uFF0C\u6709\u88AB\u968F\u610F\u4FEE\u6539\u7684\u98CE\u9669\u3002\u4F46 Entity \u548C VO \u7684\u751F\u547D\u5468\u671F\u662F\u6709\u9650\u7684\uFF0C\u90FD\u4EC5\u9650\u5728\u672C\u5C42\u8303\u56F4\u5185\uFF0C\u76F8\u5BF9\u6765\u8BF4\u662F\u5B89\u5168\u7684\u3002Service \u5C42\u5305\u542B\u6BD4\u8F83\u591A\u7684\u4E1A\u52A1\u903B\u8F91\u4EE3\u7801\uFF0C\u6240\u4EE5 BO \u5C31\u5B58\u5728\u88AB\u4EFB\u610F\u4FEE\u6539\u7684\u98CE\u9669\u4E86\u3002\u4E3A\u4E86\u4F7F\u7528\u65B9\u4FBF\uFF0C\u6211\u4EEC\u53EA\u80FD\u505A\u4E00\u4E9B\u59A5\u534F\uFF0C\u653E\u5F03 BO \u7684\u5C01\u88C5\u7279\u6027\uFF0C\u7531\u7A0B\u5E8F\u5458\u81EA\u5DF1\u6765\u8D1F\u8D23\u8FD9\u4E9B\u6570\u636E\u5BF9\u8C61\u7684\u4E0D\u88AB\u9519\u8BEF\u4F7F\u7528\u3002</p><p><strong>3. \u603B\u7ED3\u7528\u5230\u7684\u8BBE\u8BA1\u539F\u5219\u548C\u601D\u60F3</strong></p><p>\u4ECE\u8868\u9762\u4E0A\u770B\uFF0C\u505A\u4E1A\u52A1\u5F00\u53D1\u53EF\u80FD\u5E76\u4E0D\u662F\u7279\u522B\u6709\u6280\u672F\u6311\u6218\uFF0C\u4F46\u662F\u5B9E\u9645\u4E0A\uFF0C\u5982\u679C\u4F60\u8981\u505A\u5230\u77E5\u5176\u7136\u77E5\u5176\u6240\u4EE5\u7136\uFF0C\u505A\u5230\u900F\u5F7B\u7406\u89E3\u3001\u771F\u7684\u61C2\uFF0C\u5E76\u4E0D\u662F\u4EF6\u5BB9\u6613\u7684\u4E8B\u60C5\u3002\u6DF1\u6316\u4E00\u4E0B\uFF0C\u4F60\u4F1A\u53D1\u73B0\u8FD9\u5176\u4E2D\u8FD8\u662F\u8574\u542B\u4E86\u5F88\u591A\u8BBE\u8BA1\u539F\u5219\u3001\u601D\u60F3\u548C\u6A21\u5F0F\u7684\u3002</p><h2 id="\u8BFE\u5802\u8BA8\u8BBA" tabindex="-1"><a class="header-anchor" href="#\u8BFE\u5802\u8BA8\u8BBA" aria-hidden="true">#</a> \u8BFE\u5802\u8BA8\u8BBA</h2><p>\u8FD9\u4E24\u8005\u542C\u8D77\u6765\u6BD4\u8F83\u77DB\u76FE\u3002\u4F5C\u4E3A\u4E00\u540D\u6280\u672F\u4EBA\uFF0C\u4E3A\u4E86\u8C0B\u6C42\u66F4\u597D\u7684\u53D1\u5C55\uFF0C\u4F60\u89C9\u5F97\u662F\u5E94\u8BE5\u591A\u82B1\u70B9\u65F6\u95F4\u7814\u7A76\u4E1A\u52A1\u5462\uFF0C\u8FD8\u662F\u8981\u591A\u82B1\u70B9\u5FC3\u601D\u5728\u6280\u672F\u4E0A\u5462\uFF1F</p><blockquote><p>\u4E2A\u4EBA\u89C9\u5F97\uFF0C\u5982\u679C\u5BF9\u5F53\u524D\u5DE5\u4F5C\u4E0D\u6EE1\u610F\uFF0C\u60F3\u8981\u627E\u66F4\u597D\u7684\u5DE5\u4F5C\u7684\u8BDD\uFF0C\u5E94\u8BE5\u591A\u82B1\u70B9\u65F6\u95F4\u5728\u6280\u672F\u4E0A\uFF0C\u4F46\u662F\u5982\u679C\u5BF9\u5F53\u524D\u5DE5\u4F5C\u5F88\u6EE1\u610F\uFF0C\u60F3\u8981\u7EE7\u7EED\u5728\u5F53\u524D\u5C97\u4F4D\u4E0A\u53D1\u5C55\u7684\u8BDD\uFF0C\u8FD8\u662F\u5E94\u8BE5\u591A\u82B1\u65F6\u95F4\u5728\u4E1A\u52A1\u4E0A\u3002</p></blockquote><p>\u4E0A\u8282\u8BFE\u4E2D\uFF0C\u6211\u4EEC\u8BB2\u5230\uFF0C\u4E0B\u5C42\u7CFB\u7EDF\u4E0D\u8981\u5305\u542B\u592A\u591A\u4E0A\u5C42\u7CFB\u7EDF\u7684\u4E1A\u52A1\u4FE1\u606F\u3002\u4F46\u5728\u4ECA\u5929\u7684\u6570\u636E\u5E93\u8BBE\u8BA1\u4E2D\uFF0C\u79EF\u5206\u660E\u7EC6\u8868\u4E2D credit_transaction \u4E2D\u5305\u542B event_id\uFF0Cchannel_id \u8FD9\u4E9B\u8DDF\u4E0A\u5C42\u4E1A\u52A1\u76F8\u5173\u7684\u5B57\u6BB5\uFF0C\u90A3\u8FD9\u6837\u7684\u8BBE\u8BA1\u662F\u5426\u5408\u7406\u5462\uFF1F</p><blockquote><p>\u4FDD\u7559\u4E0A\u5C42\u5E94\u7528id\u548Cchannel\u5B8C\u5168\u7B26\u5408\u8BBE\u8BA1\u539F\u7406\uFF0C\u5197\u4F59\u4E1A\u52A1\u4FE1\u606F\u65B9\u4FBF\u65E5\u540E\u505A\u6570\u636E\u7EDF\u8BA1\uFF0C\u6C89\u6DC0\u6570\u636E\u8D44\u4EA7\u53CD\u63A8\u8425\u9500\u7B56\u7565\u8FED\u4EE3; \u4E00\u6B21\u6D88\u8D39\u6216\u8D5A\u53D6\u79EF\u5206\u884C\u4E3A\u53EF\u80FD\u5B58\u5728\u591A\u6B21\u8C03\u7528\u60C5\u51B5\uFF0C\u65B9\u4FBF\u5E42\u7B49\uFF0C\u4E0D\u81F3\u4E8E\u591A\u6B21\u8BB0\u8D26;\u65B9\u4FBF\u4E1A\u52A1\u7CFB\u7EDF\u67E5\u8BE2\u67D0\u6B21\u8D5A\u53D6\u6216\u6D88\u8D39\u7684\u79EF\u5206\u660E\u7EC6;\u6682\u65F6\u60F3\u5230\u8FD9\u4E48\u591A\u3002</p></blockquote><p>\u6211\u4EEC\u7ECF\u5E38\u8BF4\uFF0C\u4FEE\u6539\u548C\u67E5\u8BE2\u4E0D\u8981\u8026\u5408\u5728\u4E00\u4E2A\u63A5\u53E3\u4E2D\uFF0C\u8981\u5206\u6210\u4E24\u4E2A\u63A5\u53E3\u6765\u505A\u3002\u8D5A\u53D6\u79EF\u5206\u548C\u6D88\u8D39\u79EF\u5206\u63A5\u53E3\u8FD4\u56DE\u79EF\u5206\u660E\u7EC6 ID\uFF0C\u8FD9\u6837\u7684\u63A5\u53E3\u8BBE\u8BA1\u662F\u5426\u8FDD\u80CC\u5355\u4E00\u804C\u8D23\u539F\u5219\u5462\uFF1F\u662F\u4E0D\u662F\u8FD4\u56DE void \u6216\u8005 boolean \u7C7B\u578B\u66F4\u5408\u7406\u5462\uFF1F</p><blockquote><p>\u5C3D\u91CF\u4E0D\u8981\u8FD4\u56DEvoid\u6216boolean\uFF0C\u6709\u4E9B\u4E1A\u52A1\u9700\u8981\u53CD\u5411\u5173\u952E\u79EF\u5206\u6D41\u6C34id\u505A\u5355\u7B14\u6D41\u6C34\u67E5\u8BE2\u3002 \u5176\u5B9E\u8FD9\u4E24\u4E2A\u8BA8\u8BBA\u90FD\u7C7B\u4F3C\u4E8E\u73B0\u5B9E\u751F\u6D3B\uFF0C\u53BB\u4FBF\u5229\u5E97\u4E70\u4E1C\u897F\u4F1A\u7ED9\u4F60\u5C0F\u7968\uFF0C\u652F\u4ED8\u5B9D\u626B\u7801\u4ED8\u6B3E\u4F1A\u8FD4\u56DE\u4EA4\u6613\u6D41\u6C34\u3002\u90FD\u662F\u4E3A\u4E86\u65B9\u4FBF\u771F\u662F\u573A\u666F\u89E3\u51B3\u201C\u7EA0\u7EB7\u201D(\u67E5\u8BE2)\u7528\u7684\u3002</p></blockquote>',114);function i(t,o){return a}var h=e(r,[["render",i],["__file","\u5B9E\u6218\u4E00.html.vue"]]);export{h as default};
